import React, { useState } from 'react';
import { loginUser, registerUser, checkEmailExists, sendVerificationCode, verifyUserOtp } from '../services/storageService';
import Input from './Input';
import Button from './Button';
import { User } from '../types';

interface AuthFormsProps {
  onLogin: (user: User) => void;
  toggleMode: () => void;
  isRegistering: boolean;
}

type AuthStep = 'EMAIL' | 'VERIFY' | 'DETAILS';

const AuthForms: React.FC<AuthFormsProps> = ({ onLogin, toggleMode, isRegistering }) => {
  const [step, setStep] = useState<AuthStep>('EMAIL');

  const [email, setEmail] = useState('');
  const [otpInput, setOtpInput] = useState('');
  const [username, setUsername] = useState('');

  const [generatedOtp, setGeneratedOtp] = useState<string | null>(null);
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  // Reset state when switching modes
  const handleToggleMode = () => {
    setStep('EMAIL');
    setError('');
    setOtpInput('');
    setGeneratedOtp(null);
    toggleMode();
  };

  // Step 1: Send Code
  const handleSendCode = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!email.trim() || !email.includes('@')) {
      setError('请输入有效的电子邮箱地址。');
      return;
    }

    setIsLoading(true);

    try {
      const emailExists = await checkEmailExists(email);

      if (isRegistering && emailExists) {
        setError('该邮箱已注册，请直接登录。');
        setIsLoading(false);
        return;
      }

      if (!isRegistering && !emailExists) {
        setError('该邮箱未注册，请先注册账号。');
        setIsLoading(false);
        return;
      }

      const code = await sendVerificationCode(email);
      setGeneratedOtp(code); // Store code (if local) or status flag
      setStep('VERIFY');
    } catch (err) {
      console.error(err);
      setError('连接错误或邮箱无效，请重试。');
    }
    setIsLoading(false);
  };

  // Step 2: Verify Code
  const handleVerifyCode = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    let isValid = false;

    // Local/Admin Backdoor check
    if (generatedOtp && generatedOtp !== "SENT_VIA_EMAIL") {
       isValid = otpInput === generatedOtp;
    } else {
       // Real Supabase verification
       isValid = await verifyUserOtp(email, otpInput);
    }

    if (!isValid) {
      setError('验证码无效，请重试。');
      setIsLoading(false);
      return;
    }

    // Code matches
    if (isRegistering) {
      setStep('DETAILS'); // Move to username entry
      setIsLoading(false);
    } else {
      // Login directly
      try {
        const result = await loginUser(email);
        if (result.success && result.user) {
          onLogin(result.user);
        } else {
          setError(result.message || '登录失败');
        }
      } catch (err) {
        setError('登录过程中发生错误。');
      }
      setIsLoading(false);
    }
  };

  // Step 3: Complete Registration (Only for Register mode)
  const handleCompleteRegistration = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    if (!username.trim()) {
      setError('请输入用户名。');
      setIsLoading(false);
      return;
    }

    // New validation: Allow Alphanumeric + Underscore + Chinese characters
    const usernameRegex = /^[a-zA-Z0-9_\u4e00-\u9fa5]+$/;
    if (!usernameRegex.test(username)) {
      setError('用户名只能包含字母、数字、中文和下划线，不能包含空格或特殊字符。');
      setIsLoading(false);
      return;
    }

    // Adjusted length check for Chinese names (e.g. "王伟" is 2 chars)
    if (username.length < 2 || username.length > 20) {
      setError('用户名长度需在 2 到 20 个字符之间。');
      setIsLoading(false);
      return;
    }

    try {
      const result = await registerUser(email, username);
      if (result.success) {
        // Auto login
        const loginResult = await loginUser(email);
        if (loginResult.success && loginResult.user) {
          onLogin(loginResult.user);
        }
      } else {
        setError(result.message);
      }
    } catch (err) {
      setError('注册失败。');
    }
    setIsLoading(false);
  };

  return (
    <div className="max-w-md mx-auto w-full bg-slate-800 p-8 rounded-2xl shadow-2xl border border-slate-700 animate-fade-in-up mt-20">
      <div className="text-center mb-8 flex flex-col items-center">
        <img 
          src="/assets/ui/logo.png" 
          alt="Assetto Corsa Competizione" 
          className="h-16 w-auto object-contain mb-4"
        />
        <h2 className="text-xl font-bold text-white tracking-widest uppercase">Tracker<span className="text-red-500">Pro</span></h2>
        <p className="text-slate-400 mt-2">
          {isRegistering ? '创建车手档案' : '欢迎回来，车手'}
        </p>
      </div>

      {/* Step 1: Email Input */}
      {step === 'EMAIL' && (
        <form onSubmit={handleSendCode} className="space-y-6">
          <Input
            label="电子邮箱"
            type="email"
            placeholder="name@example.com"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            disabled={isLoading}
            autoFocus
          />
          {error && <div className="text-red-500 text-sm text-center font-bold">{error}</div>}
          <Button type="submit" className="w-full py-3 text-lg" isLoading={isLoading}>
            {isLoading ? '发送中...' : '获取验证码'}
          </Button>
        </form>
      )}

      {/* Step 2: OTP Verification */}
      {step === 'VERIFY' && (
        <form onSubmit={handleVerifyCode} className="space-y-6 animate-fade-in">
          <div className="text-center text-slate-400 text-sm mb-4">
            我们已发送验证码至 <span className="text-white font-bold">{email}</span>
            {generatedOtp === "SENT_VIA_EMAIL" && <p className="text-xs text-slate-500 mt-1">(请检查垃圾邮件文件夹)</p>}
          </div>
          <Input
            label="验证码 / 密码"
            type="text"
            placeholder="12345678"
            value={otpInput}
            onChange={(e) => setOtpInput(e.target.value)}
            className="text-center tracking-[0.2em] font-mono text-xl"
            maxLength={30}
            autoFocus
            disabled={isLoading}
          />
          {error && <div className="text-red-500 text-sm text-center font-bold">{error}</div>}
          <Button type="submit" className="w-full py-3 text-lg" isLoading={isLoading}>
            验证并{isRegistering ? '继续' : '登录'}
          </Button>
          <button 
            type="button" 
            onClick={() => setStep('EMAIL')}
            className="w-full text-slate-500 text-sm hover:text-white"
          >
            更换邮箱
          </button>
        </form>
      )}

      {/* Step 3: Username (Register Only) */}
      {step === 'DETAILS' && (
        <form onSubmit={handleCompleteRegistration} className="space-y-6 animate-fade-in">
          <div className="bg-green-900/20 border border-green-900/50 text-green-400 p-3 rounded text-center text-sm mb-4">
             ✓ 邮箱已验证
          </div>
          <Input
            label="车手昵称 (用户名)"
            placeholder="例如：MaxVerstappen33"
            value={username}
            onChange={(e) => setUsername(e.target.value)}
            autoFocus
            disabled={isLoading}
            autoComplete="username"
          />
          <p className="text-xs text-slate-500 mt-1">
            * 支持中文、字母、数字和下划线
          </p>
          {error && <div className="text-red-500 text-sm text-center font-bold">{error}</div>}
          <Button type="submit" className="w-full py-3 text-lg" isLoading={isLoading}>
            完成注册
          </Button>
        </form>
      )}

      <div className="mt-6 text-center pt-6 border-t border-slate-700">
        <p className="text-slate-500 text-sm">
          {isRegistering ? "已有账号？" : "新加入比赛？"}{' '}
          <button onClick={handleToggleMode} className="text-red-500 hover:text-red-400 font-bold ml-1">
            {isRegistering ? '立即登录' : '立即注册'}
          </button>
        </p>
      </div>
    </div>
  );
};

export default AuthForms;

import React, { useState, useRef } from 'react';
import { Track, User, LapTime } from '../types';
import { CARS } from '../constants';
import { submitLapTime } from '../services/storageService';
import Button from './Button';
import Input from './Input';
import { GoogleGenAI, Type } from "@google/genai";

interface SubmitLapFormProps {
  track: Track;
  user: User;
  onSuccess: () => void;
  onCancel: () => void;
}

const SubmitLapForm: React.FC<SubmitLapFormProps> = ({ track, user, onSuccess, onCancel }) => {
  const [carId, setCarId] = useState(CARS[0].id);
  const [minutes, setMinutes] = useState('');
  const [seconds, setSeconds] = useState('');
  const [millis, setMillis] = useState('');
  const [conditions, setConditions] = useState<'Dry' | 'Wet'>('Dry');

  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // AI Analysis State
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // 1. Preview
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      setPreviewImage(base64String);
      analyzeScreenshot(base64String); // Auto-start analysis
    };
    reader.readAsDataURL(file);
  };

  const analyzeScreenshot = async (base64Full: string) => {
    setIsAnalyzing(true);
    setError('');

    try {
      // Clean base64 string (remove data:image/png;base64, prefix)
      const base64Data = base64Full.split(',')[1];
      const mimeType = base64Full.split(';')[0].split(':')[1];

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Prepare Car List for the AI to match against
      const carListContext = CARS.map(c => `ID: "${c.id}", Name: "${c.brand} ${c.name}"`).join('\n');

      const prompt = `
        Analyze this Assetto Corsa Competizione screenshot (HUD or Dashboard).
        1. Identify the Lap Time (Current Lap, Last Lap, or Best Lap). Look for format MM:SS.ms.
        2. Identify the Car Model from the dashboard logo, steering wheel, or UI.
        3. Match the car to one of the IDs in the following list. If uncertain, pick the closest match or return null.

        Car List:
        ${carListContext}
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { mimeType: mimeType, data: base64Data } },
            { text: prompt }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              minutes: { type: Type.INTEGER },
              seconds: { type: Type.INTEGER },
              milliseconds: { type: Type.INTEGER },
              carId: { type: Type.STRING, description: "The exact ID from the provided list" },
              confidence: { type: Type.NUMBER, description: "Confidence score 0-1" }
            },
            required: ["minutes", "seconds", "milliseconds"]
          }
        }
      });

      const resultText = response.text;
      if (resultText) {
        const data = JSON.parse(resultText);

        if (data.minutes !== undefined) setMinutes(data.minutes.toString());
        if (data.seconds !== undefined) setSeconds(data.seconds.toString());
        if (data.milliseconds !== undefined) setMillis(data.milliseconds.toString());

        if (data.carId && CARS.some(c => c.id === data.carId)) {
          setCarId(data.carId);
        }
      }

    } catch (err: any) {
      console.error("AI Analysis Failed:", err);
      setError("AI 识别失败，请手动输入或重试。(" + (err.message || 'Unknown error') + ")");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMessage('');
    setIsSubmitting(true);

    const m = parseInt(minutes);
    const s = parseInt(seconds);
    const ms = parseInt(millis);

    if (isNaN(m) || isNaN(s) || isNaN(ms)) {
      setError('请输入有效的数字。');
      setIsSubmitting(false);
      return;
    }
    if (s >= 60) {
      setError('秒数必须小于60。');
      setIsSubmitting(false);
      return;
    }
    if (ms >= 1000) {
      setError('毫秒数必须小于1000。');
      setIsSubmitting(false);
      return;
    }

    const totalMilliseconds = (m * 60 * 1000) + (s * 1000) + ms;

    const generateId = () => {
      if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
      }
      return Date.now().toString(36) + Math.random().toString(36).substr(2);
    };

    const newLap: LapTime = {
      id: generateId(),
      username: user.username,
      userEmail: user.email, 
      trackId: track.id,
      carId,
      minutes: m,
      seconds: s,
      milliseconds: ms,
      totalMilliseconds,
      timestamp: new Date().toISOString(),
      conditions
    };

    const result = await submitLapTime(newLap);

    if (result.success) {
      setSuccessMessage(result.message);
      setTimeout(() => {
        onSuccess();
      }, 1500);
    } else {
      setError(result.message);
    }
    setIsSubmitting(false);
  };

  return (
    <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-2xl max-w-lg mx-auto w-full animate-fade-in-up">
      <h2 className="text-2xl font-bold text-white mb-6 flex items-center gap-2">
        <span className="text-red-500">录入圈速:</span> {track.name}
      </h2>

      {/* AI Upload Section */}
      <div className="mb-6 p-4 bg-slate-900/50 rounded-lg border border-slate-700 border-dashed hover:border-red-500/50 transition-colors">
        <input 
          type="file" 
          accept="image/*" 
          className="hidden" 
          ref={fileInputRef}
          onChange={handleImageUpload}
        />

        {!previewImage ? (
          <button 
            type="button"
            onClick={() => fileInputRef.current?.click()}
            className="w-full flex flex-col items-center justify-center gap-2 py-4 text-slate-400 hover:text-white transition-colors"
          >
            <div className="bg-slate-800 p-3 rounded-full">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
            </div>
            <span className="text-sm font-bold">上传截图自动识别 (AI)</span>
            <span className="text-xs text-slate-500">支持游戏截图、照片</span>
          </button>
        ) : (
          <div className="relative">
            <img 
              src={previewImage} 
              alt="Preview" 
              className="w-full h-32 object-cover rounded-lg opacity-80" 
            />
            {isAnalyzing && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/60 backdrop-blur-sm rounded-lg">
                 <span className="w-8 h-8 border-4 border-red-500 border-t-transparent rounded-full animate-spin mb-2"></span>
                 <span className="text-white font-bold text-sm shadow-black drop-shadow-md">正在分析仪表盘...</span>
              </div>
            )}
            {!isAnalyzing && (
              <button 
                type="button"
                onClick={() => {
                  setPreviewImage(null);
                  setMinutes('');
                  setSeconds('');
                  setMillis('');
                }}
                className="absolute top-2 right-2 bg-black/50 text-white rounded-full p-1 hover:bg-red-600 transition-colors"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                </svg>
              </button>
            )}
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">

        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">选择车辆</label>
          <select 
            value={carId} 
            onChange={(e) => setCarId(e.target.value)}
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:border-red-500 focus:outline-none focus:ring-1 focus:ring-red-500"
          >
            {CARS.map(car => (
              <option key={car.id} value={car.id}>
                [{car.class}] {car.brand} {car.name}
              </option>
            ))}
          </select>
        </div>

        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">圈速成绩</label>
          <div className="flex items-end gap-2">
            <div className="flex-1">
              <Input 
                placeholder="0" 
                type="number" 
                min="0"
                value={minutes}
                onChange={(e) => setMinutes(e.target.value)}
                required
                className={isAnalyzing ? 'opacity-50' : ''}
              />
              <span className="text-xs text-slate-500 text-center block mt-1">分</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">:</span>
            <div className="flex-1">
              <Input 
                placeholder="00" 
                type="number" 
                min="0" max="59"
                value={seconds}
                onChange={(e) => setSeconds(e.target.value)}
                required
                className={isAnalyzing ? 'opacity-50' : ''}
              />
              <span className="text-xs text-slate-500 text-center block mt-1">秒</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">.</span>
            <div className="flex-1">
              <Input 
                placeholder="000" 
                type="number" 
                min="0" max="999"
                value={millis}
                onChange={(e) => setMillis(e.target.value)}
                required
                className={isAnalyzing ? 'opacity-50' : ''}
              />
              <span className="text-xs text-slate-500 text-center block mt-1">毫秒</span>
            </div>
          </div>
        </div>

        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">赛道状况</label>
          <div className="flex gap-4">
            <button
              type="button"
              onClick={() => setConditions('Dry')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Dry' 
                  ? 'bg-orange-500/20 border-orange-500 text-orange-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              ☀️ 干地
            </button>
            <button
              type="button"
              onClick={() => setConditions('Wet')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Wet' 
                  ? 'bg-blue-500/20 border-blue-500 text-blue-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              🌧️ 湿地
            </button>
          </div>
        </div>

        {error && (
          <div className="bg-yellow-900/50 border border-yellow-500/50 text-yellow-200 px-4 py-3 rounded text-sm font-semibold break-words">
            ⚠️ {error}
          </div>
        )}

        {successMessage && (
           <div className="bg-green-900/50 border border-green-500/50 text-green-200 px-4 py-3 rounded text-sm font-semibold flex items-center gap-2">
             ✅ {successMessage}
           </div>
        )}

        <div className="flex gap-3 pt-4">
          <Button type="button" variant="ghost" onClick={onCancel} className="flex-1" disabled={isSubmitting || isAnalyzing}>
            返回
          </Button>
          <Button type="submit" className="flex-1" disabled={!!successMessage || isSubmitting || isAnalyzing} isLoading={isSubmitting}>
            提交成绩
          </Button>
        </div>
      </form>
    </div>
  );
};

export default SubmitLapForm;

