import React, { useState, useRef } from 'react';
import { Track, User, LapTime, InputDevice } from '../types';
import { CARS, TRACKS } from '../constants';
import { submitLapTime } from '../services/storageService';
import Button from './Button';
import Input from './Input';
import InputDeviceIcon from './InputDeviceIcon';
import { GoogleGenAI, Type } from "@google/genai";

interface SubmitLapFormProps {
  track: Track;
  user: User;
  onSuccess: () => void;
  onCancel: () => void;
}

const SubmitLapForm: React.FC<SubmitLapFormProps> = ({ track: initialTrack, user, onSuccess, onCancel }) => {
  // State
  const [targetTrackId, setTargetTrackId] = useState(initialTrack.id);
  const [carId, setCarId] = useState(CARS[0].id);
  const [minutes, setMinutes] = useState('');
  const [seconds, setSeconds] = useState('');
  const [millis, setMillis] = useState('');
  const [conditions, setConditions] = useState<'Dry' | 'Wet'>('Dry');
  const [trackTemp, setTrackTemp] = useState('');
  const [inputDevice, setInputDevice] = useState<InputDevice>('Wheel');

  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // AI Analysis State
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // 1. Preview
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      setPreviewImage(base64String);
      analyzeScreenshot(base64String); // Auto-start analysis
    };
    reader.readAsDataURL(file);
  };

  const analyzeScreenshot = async (base64Full: string) => {
    setIsAnalyzing(true);
    setError('');

    try {
      // Clean base64 string (remove data:image/png;base64, prefix)
      const base64Data = base64Full.split(',')[1];
      const mimeType = base64Full.split(';')[0].split(':')[1];

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Prepare Contexts
      const carListContext = CARS.map(c => `ID: "${c.id}", Name: "${c.brand} ${c.name}"`).join('\n');
      const trackListContext = TRACKS.map(t => `ID: "${t.id}", Name: "${t.name}"`).join('\n');

      const prompt = `
        Analyze this Assetto Corsa Competizione screenshot.

        Tasks:
        1. Identify the Lap Time (MM:SS.ms).
        2. Identify the Car Model and match to the provided Car List.
        3. Identify the Track Name from the UI/Environment and match to the provided Track List.
        4. Identify Track Temperature (e.g., "Track: 24°C").

        Lists:
        [CARS]
        ${carListContext}

        [TRACKS]
        ${trackListContext}
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { mimeType: mimeType, data: base64Data } },
            { text: prompt }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              minutes: { type: Type.INTEGER },
              seconds: { type: Type.INTEGER },
              milliseconds: { type: Type.INTEGER },
              carId: { type: Type.STRING, description: "ID from Car List" },
              trackId: { type: Type.STRING, description: "ID from Track List" },
              trackTemp: { type: Type.INTEGER },
            },
            required: ["minutes", "seconds", "milliseconds"]
          }
        }
      });

      const resultText = response.text;
      if (resultText) {
        const data = JSON.parse(resultText);

        if (data.minutes !== undefined) setMinutes(data.minutes.toString());
        if (data.seconds !== undefined) setSeconds(data.seconds.toString());
        if (data.milliseconds !== undefined) setMillis(data.milliseconds.toString());
        if (data.trackTemp !== undefined) setTrackTemp(data.trackTemp.toString());

        if (data.carId && CARS.some(c => c.id === data.carId)) {
          setCarId(data.carId);
        }

        if (data.trackId && TRACKS.some(t => t.id === data.trackId)) {
          setTargetTrackId(data.trackId);
        }
      }

    } catch (err: any) {
      console.error("AI Analysis Failed:", err);
      setError("AI 识别失败，请确保截图清晰包含数据。(" + (err.message || 'Unknown error') + ")");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMessage('');
    setIsSubmitting(true);

    const m = parseInt(minutes);
    const s = parseInt(seconds);
    const ms = parseInt(millis);
    const tTemp = trackTemp ? parseInt(trackTemp) : undefined;

    if (isNaN(m) || isNaN(s) || isNaN(ms)) {
      setError('请先上传包含有效圈速的截图。');
      setIsSubmitting(false);
      return;
    }
    if (s >= 60) {
      setError('秒数必须小于60。');
      setIsSubmitting(false);
      return;
    }
    if (ms >= 1000) {
      setError('毫秒数必须小于1000。');
      setIsSubmitting(false);
      return;
    }

    const totalMilliseconds = (m * 60 * 1000) + (s * 1000) + ms;

    const generateId = () => {
      if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
      }
      return Date.now().toString(36) + Math.random().toString(36).substr(2);
    };

    const newLap: LapTime = {
      id: generateId(),
      username: user.username,
      userEmail: user.email, 
      trackId: targetTrackId, // Use the AI detected track ID
      carId,
      minutes: m,
      seconds: s,
      milliseconds: ms,
      totalMilliseconds,
      timestamp: new Date().toISOString(),
      conditions,
      trackTemp: tTemp,
      inputDevice
    };

    const result = await submitLapTime(newLap);

    if (result.success) {
      setSuccessMessage(result.message);
      setTimeout(() => {
        onSuccess();
      }, 1500);
    } else {
      setError(result.message);
    }
    setIsSubmitting(false);
  };

  const currentTrack = TRACKS.find(t => t.id === targetTrackId) || initialTrack;

  return (
    <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-2xl max-w-lg mx-auto w-full animate-fade-in-up">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold text-white flex items-center gap-2">
          <span className="text-red-500">录入圈速</span>
        </h2>
        <div className="text-xs bg-slate-900 px-3 py-1 rounded-full border border-slate-700 text-slate-400">
           AI 辅助模式
        </div>
      </div>

      {/* AI Upload Section */}
      <div className="mb-6 p-4 bg-slate-900/50 rounded-lg border border-slate-700 border-dashed hover:border-red-500/50 transition-colors">
        <input 
          type="file" 
          accept="image/*" 
          className="hidden" 
          ref={fileInputRef}
          onChange={handleImageUpload}
        />

        {!previewImage ? (
          <button 
            type="button"
            onClick={() => fileInputRef.current?.click()}
            className="w-full flex flex-col items-center justify-center gap-2 py-4 text-slate-400 hover:text-white transition-colors"
          >
            <div className="bg-slate-800 p-3 rounded-full animate-bounce">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
            </div>
            <span className="text-sm font-bold">点击上传游戏截图</span>
            <span className="text-xs text-slate-500">必须上传截图以自动填充数据</span>
          </button>
        ) : (
          <div className="relative">
            <img 
              src={previewImage} 
              alt="Preview" 
              className="w-full h-32 object-cover rounded-lg opacity-80" 
            />
            {isAnalyzing && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/60 backdrop-blur-sm rounded-lg">
                 <span className="w-8 h-8 border-4 border-red-500 border-t-transparent rounded-full animate-spin mb-2"></span>
                 <span className="text-white font-bold text-sm shadow-black drop-shadow-md">正在识别赛道与圈速...</span>
              </div>
            )}
            {!isAnalyzing && (
              <button 
                type="button"
                onClick={() => {
                  setPreviewImage(null);
                  setMinutes('');
                  setSeconds('');
                  setMillis('');
                  setTrackTemp('');
                  setTargetTrackId(initialTrack.id);
                }}
                className="absolute top-2 right-2 bg-black/50 text-white rounded-full p-1 hover:bg-red-600 transition-colors"
                title="清除并重新上传"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                </svg>
              </button>
            )}
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Track Display (Read Only) */}
        <div>
           <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">识别到的赛道 (锁定)</label>
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-slate-500" viewBox="0 0 20 20" fill="currentColor">
               <title>数据由截图自动识别</title>
               <path fillRule="evenodd" d="M5 9V7a5 5 0 0110 0v2a2 2 0 012 2v5a2 2 0 01-2 2H5a2 2 0 01-2-2v-5a2 2 0 012-2zm8-2v2H7V7a3 3 0 016 0z" clipRule="evenodd" />
             </svg>
           </div>
           <div className={`flex items-center gap-3 p-3 bg-slate-950 border border-slate-800 rounded-lg ${isAnalyzing ? 'opacity-50' : ''}`}>
              {currentTrack.imageUrl && (
                 <img src={currentTrack.imageUrl} className="h-8 w-8 object-contain brightness-0 invert opacity-50" alt="Track Icon"/>
              )}
              <div className="flex-1">
                 <div className="text-white font-bold">{currentTrack.name}</div>
                 <div className="text-xs text-slate-500">{currentTrack.country} • {currentTrack.length}</div>
              </div>
              <div className="text-xs text-slate-600 font-mono">{currentTrack.id}</div>
           </div>
        </div>

        {/* Car Selection */}
        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">识别到的车辆 (可修正)</label>
          <select 
            value={carId} 
            onChange={(e) => setCarId(e.target.value)}
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:border-red-500 focus:outline-none focus:ring-1 focus:ring-red-500"
          >
            {CARS.map(car => (
              <option key={car.id} value={car.id}>
                [{car.class}] {car.brand} {car.name}
              </option>
            ))}
          </select>
        </div>

        {/* Lap Time Inputs (Read Only) */}
        <div>
          <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">圈速成绩 (锁定)</label>
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-slate-500" viewBox="0 0 20 20" fill="currentColor">
               <title>数据由截图自动识别</title>
               <path fillRule="evenodd" d="M5 9V7a5 5 0 0110 0v2a2 2 0 012 2v5a2 2 0 01-2 2H5a2 2 0 01-2-2v-5a2 2 0 012-2zm8-2v2H7V7a3 3 0 016 0z" clipRule="evenodd" />
             </svg>
          </div>
          <div className="flex items-end gap-2">
            <div className="flex-1">
              <Input 
                placeholder="--" 
                value={minutes}
                readOnly
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : 'bg-slate-950 text-slate-400 cursor-not-allowed border-slate-800'}`}
              />
              <span className="text-xs text-slate-500 text-center block mt-1">分</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">:</span>
            <div className="flex-1">
              <Input 
                placeholder="--" 
                value={seconds}
                readOnly
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : 'bg-slate-950 text-slate-400 cursor-not-allowed border-slate-800'}`}
              />
              <span className="text-xs text-slate-500 text-center block mt-1">秒</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">.</span>
            <div className="flex-1">
              <Input 
                placeholder="---" 
                value={millis}
                readOnly
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : 'bg-slate-950 text-slate-400 cursor-not-allowed border-slate-800'}`}
              />
              <span className="text-xs text-slate-500 text-center block mt-1">毫秒</span>
            </div>
          </div>
          {!minutes && !isAnalyzing && (
            <p className="text-xs text-red-500/70 mt-2 text-center">* 请上传截图以获取圈速</p>
          )}
        </div>

        <div className="grid grid-cols-2 gap-4">
           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">赛道温度 (°C)</label>
              <div className="relative">
                <Input
                  type="number"
                  placeholder="24"
                  value={trackTemp}
                  onChange={(e) => setTrackTemp(e.target.value)}
                  className={isAnalyzing ? 'opacity-50' : ''}
                />
                <span className="absolute right-4 top-3.5 text-slate-500">°C</span>
              </div>
           </div>

           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">输入设备</label>
              <div className="flex flex-col gap-2">
                 <div className="grid grid-cols-3 gap-2">
                    {(['Wheel', 'Gamepad', 'Keyboard'] as InputDevice[]).map((dev) => (
                      <button
                        key={dev}
                        type="button"
                        onClick={() => setInputDevice(dev)}
                        className={`flex flex-col items-center justify-center p-3 rounded-lg border transition-all ${
                          inputDevice === dev
                            ? 'bg-red-600 border-red-500 text-white shadow-lg shadow-red-900/20'
                            : 'bg-slate-900 border-slate-700 text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                        }`}
                        title={dev === 'Wheel' ? '方向盘' : dev === 'Gamepad' ? '手柄' : '键盘'}
                      >
                        <InputDeviceIcon device={dev} className="h-8 w-8" />
                      </button>
                    ))}
                 </div>
              </div>
           </div>
        </div>

        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">赛道状况</label>
          <div className="flex gap-4">
            <button
              type="button"
              onClick={() => setConditions('Dry')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Dry' 
                  ? 'bg-orange-500/20 border-orange-500 text-orange-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              ☀️ 干地
            </button>
            <button
              type="button"
              onClick={() => setConditions('Wet')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Wet' 
                  ? 'bg-blue-500/20 border-blue-500 text-blue-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              🌧️ 湿地
            </button>
          </div>
        </div>

        {error && (
          <div className="bg-yellow-900/50 border border-yellow-500/50 text-yellow-200 px-4 py-3 rounded text-sm font-semibold break-words">
            ⚠️ {error}
          </div>
        )}

        {successMessage && (
           <div className="bg-green-900/50 border border-green-500/50 text-green-200 px-4 py-3 rounded text-sm font-semibold flex items-center gap-2">
             ✅ {successMessage}
           </div>
        )}

        <div className="flex gap-3 pt-4">
          <Button type="button" variant="ghost" onClick={onCancel} className="flex-1" disabled={isSubmitting || isAnalyzing}>
            返回
          </Button>
          <Button type="submit" className="flex-1" disabled={!!successMessage || isSubmitting || isAnalyzing || !minutes} isLoading={isSubmitting}>
            提交成绩
          </Button>
        </div>
      </form>
    </div>
  );
};

export default SubmitLapForm;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Track, Car, LapTime, InputDevice } from '../types';
import { CARS } from '../constants';
import { fetchLapTimes, deleteLapTime } from '../services/storageService';
import Button from './Button';
import InputDeviceIcon from './InputDeviceIcon';

interface LeaderboardProps {
  selectedTrack: Track;
  currentUser: string | undefined;
}

const Leaderboard: React.FC<LeaderboardProps> = ({ selectedTrack, currentUser }) => {
  const [times, setTimes] = useState<LapTime[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [filterClass, setFilterClass] = useState<string>('ALL');
  const [selectedDriver, setSelectedDriver] = useState<string | null>(null);

  // Sticky User Row State
  const [stickyState, setStickyState] = useState<'top' | 'bottom' | null>(null);

  // Delete Modal State
  const [lapToDelete, setLapToDelete] = useState<string | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  // Helper to reload data
  const loadData = async () => {
    setIsLoading(true);
    const loadedTimes = await fetchLapTimes(selectedTrack.id);
    setTimes(loadedTimes);
    setIsLoading(false);
    // Note: We don't reset selectedDriver here to allow refreshing the list after delete while staying in view
    // But if we delete the last lap, we might want to handle that.
    setStickyState(null);
  };

  useEffect(() => {
    loadData();
    setSelectedDriver(null); // Reset detail view only when track changes
  }, [selectedTrack]);

  const getCarName = (carId: string) => {
    const car = CARS.find(c => c.id === carId);
    return car ? `${car.brand} ${car.name}` : carId;
  };

  const getCarClass = (carId: string) => {
    return CARS.find(c => c.id === carId)?.class || 'GT3';
  };

  // 1. Filter raw times by selected class (if not ALL)
  const classFilteredTimes = useMemo(() => {
    return filterClass === 'ALL' 
      ? times 
      : times.filter(t => getCarClass(t.carId) === filterClass);
  }, [times, filterClass]);

  // 2. LEVEL 1 DATA: Group by User, keeping only their BEST time
  const uniqueDriverTimes = useMemo(() => {
    const bestTimesMap = new Map<string, LapTime>();

    classFilteredTimes.forEach(time => {
      const existing = bestTimesMap.get(time.username);
      if (!existing || time.totalMilliseconds < existing.totalMilliseconds) {
        bestTimesMap.set(time.username, time);
      }
    });

    return Array.from(bestTimesMap.values()).sort((a, b) => a.totalMilliseconds - b.totalMilliseconds);
  }, [classFilteredTimes]);

  // 3. LEVEL 2 DATA: Get all times for the selected driver (on this track)
  const selectedDriverTimes = useMemo(() => {
    if (!selectedDriver) return [];
    return times
      .filter(t => t.username === selectedDriver)
      .sort((a, b) => a.totalMilliseconds - b.totalMilliseconds);
  }, [times, selectedDriver]);

  // Find User's stats for sticky row
  const currentUserStats = useMemo(() => {
    if (!currentUser) return null;
    const index = uniqueDriverTimes.findIndex(t => t.username === currentUser);
    if (index === -1) return null;
    return {
      rank: index + 1,
      data: uniqueDriverTimes[index]
    };
  }, [uniqueDriverTimes, currentUser]);

  // Format helper: 1:47.500
  const formatTime = (t: LapTime | undefined) => {
    if (!t || typeof t.minutes === 'undefined') return '--:--.---';
    return `${t.minutes}:${t.seconds?.toString().padStart(2, '0')}.${t.milliseconds?.toString().padStart(3, '0')}`;
  };

  const handleRequestDelete = (lapId: string) => {
    setLapToDelete(lapId);
  };

  const confirmDelete = async () => {
    if (!lapToDelete) return;
    setIsDeleting(true);

    const result = await deleteLapTime(lapToDelete);

    if (result.success) {
      await loadData(); // Refresh data

      // If user deleted their last lap, go back to main view
      // We need to re-calc remaining laps based on the old state minus the deleted one
      const remainingLaps = selectedDriverTimes.filter(t => t.id !== lapToDelete);
      if (remainingLaps.length === 0) {
        setSelectedDriver(null);
      }
    } else {
      alert("删除失败: " + result.message);
    }

    setIsDeleting(false);
    setLapToDelete(null);
  };

  // --- Sticky Row Logic ---
  useEffect(() => {
    if (!currentUserStats || selectedDriver) { // Don't sticky if in detail view or no user data
      setStickyState(null);
      return;
    }

    const checkVisibility = () => {
      const element = document.getElementById('current-user-row');
      if (!element) return;

      const rect = element.getBoundingClientRect();
      const viewportHeight = window.innerHeight;

      // Offset for sticky header (Navbar + Track Header approx 130px)
      const topThreshold = 140; 

      if (rect.bottom < topThreshold) {
        setStickyState('top');
      } else if (rect.top > viewportHeight) {
        setStickyState('bottom');
      } else {
        setStickyState(null);
      }
    };

    window.addEventListener('scroll', checkVisibility);
    window.addEventListener('resize', checkVisibility);

    // Initial check
    checkVisibility();

    return () => {
      window.removeEventListener('scroll', checkVisibility);
      window.removeEventListener('resize', checkVisibility);
    };
  }, [currentUserStats, selectedDriver]);

  const scrollToUserRow = () => {
    const element = document.getElementById('current-user-row');
    if (element) {
      element.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  };

  // --- RENDER HELPERS ---

  const renderConditions = (cond: 'Dry'|'Wet', temp?: number) => {
    return (
       <div className="flex flex-col items-center">
          <span className={`text-xs px-2 py-0.5 rounded border mb-0.5 ${
            cond === 'Wet' 
            ? 'bg-blue-900/30 text-blue-400 border-blue-800' 
            : 'bg-orange-900/30 text-orange-400 border-orange-800'
          }`}>
            {cond}
          </span>
          {temp !== undefined && <span className="text-[10px] text-slate-500">{temp}°C</span>}
       </div>
    )
  }

  const renderLevel1 = () => {
    // Get the absolute best time for Gap calculation
    const overallBestTime = uniqueDriverTimes.length > 0 ? uniqueDriverTimes[0].totalMilliseconds : 0;

    return (
    <div className="bg-slate-800/50 rounded-xl overflow-hidden border border-slate-700 backdrop-blur-sm animate-fade-in relative">
      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-900/80 text-slate-400 text-xs uppercase tracking-wider border-b border-slate-700">
              <th className="px-6 py-4 font-bold text-center">Pos</th>
              <th className="px-6 py-4 font-bold">Driver</th>
              <th className="px-6 py-4 font-bold">Best Time</th>
              <th className="px-6 py-4 font-bold">Gap</th>
              <th className="px-6 py-4 font-bold">Car Used</th>
              <th className="px-6 py-4 font-bold text-center">Env.</th>
              <th className="px-6 py-4 font-bold text-center">Input</th>
              <th className="px-6 py-4 font-bold text-right">Details</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-700/50">
            {isLoading ? (
               <tr>
                <td colSpan={8} className="px-6 py-12 text-center text-slate-500">
                  <div className="flex justify-center items-center gap-3">
                    <span className="w-5 h-5 border-2 border-slate-500 border-t-transparent rounded-full animate-spin"></span>
                    <span>Loading Telemetry...</span>
                  </div>
                </td>
              </tr>
            ) : uniqueDriverTimes.length === 0 ? (
              <tr>
                <td colSpan={8} className="px-6 py-12 text-center text-slate-500 italic">
                  No lap times recorded yet for this class. Be the first!
                </td>
              </tr>
            ) : (
              uniqueDriverTimes.map((time, index) => {
                const isCurrentUser = time.username === currentUser;

                // Calculate Gap
                const gap = time.totalMilliseconds - overallBestTime;
                const gapStr = index === 0 ? '-' : `+${(gap / 1000).toFixed(3)}`;

                return (
                  <tr 
                    key={time.id}
                    id={isCurrentUser ? 'current-user-row' : undefined}
                    onClick={() => setSelectedDriver(time.username)}
                    className={`group transition-colors cursor-pointer ${
                      isCurrentUser ? 'bg-red-900/20 hover:bg-red-900/30 border-l-4 border-l-red-500' : 'hover:bg-slate-700/30'
                    }`}
                  >
                    <td className="px-6 py-4 text-center">
                      <span className={`inline-flex items-center justify-center w-8 h-8 rounded-full font-bold text-sm ${
                        index === 0 ? 'bg-yellow-500/20 text-yellow-400 border border-yellow-500/50' :
                        index === 1 ? 'bg-slate-400/20 text-slate-300 border border-slate-400/50' :
                        index === 2 ? 'bg-orange-700/20 text-orange-400 border border-orange-700/50' :
                        'text-slate-500'
                      }`}>
                        {index + 1}
                      </span>
                    </td>
                    <td className="px-6 py-4 font-medium text-white">
                      {time.username}
                      {isCurrentUser && <span className="ml-2 text-[10px] uppercase bg-red-600 px-1.5 py-0.5 rounded text-white">You</span>}
                    </td>
                    <td className="px-6 py-4 font-mono text-lg font-bold text-red-400 group-hover:text-red-300">
                      {formatTime(time)}
                    </td>
                    <td className="px-6 py-4 font-mono text-sm text-slate-400">
                      {gapStr}
                    </td>
                    <td className="px-6 py-4 text-slate-300 text-sm">
                      <div className="flex flex-col">
                        <span className="truncate max-w-[200px]">{getCarName(time.carId)}</span>
                        <span className="text-[10px] text-slate-500 bg-slate-800 w-fit px-1 rounded mt-0.5">{getCarClass(time.carId)}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-center">
                      {renderConditions(time.conditions, time.trackTemp)}
                    </td>
                    <td className="px-6 py-4 text-center">
                      <div className="flex justify-center items-center text-slate-500">
                         <InputDeviceIcon device={time.inputDevice} />
                      </div>
                    </td>
                    <td className="px-6 py-4 text-right text-slate-500">
                       <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 ml-auto group-hover:text-white transition-colors" viewBox="0 0 20 20" fill="currentColor">
                          <path fillRule="evenodd" d="M7.293 14.707a1 1 0 010-1.414L10.586 10 7.293 6.707a1 1 0 011.414-1.414l4 4a1 1 0 010 1.414l-4 4a1 1 0 01-1.414 0z" clipRule="evenodd" />
                        </svg>
                    </td>
                  </tr>
                );
              })
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
  }

  const renderLevel2 = () => {
    // Check if the current logged-in user is viewing their own profile
    const isOwner = currentUser === selectedDriver;

    return (
    <div className="animate-fade-in-up">
      <div className="flex items-center justify-between mb-4 bg-slate-800/80 p-4 rounded-lg border border-slate-700">
        <div className="flex items-center gap-4">
          <Button variant="secondary" onClick={() => setSelectedDriver(null)} className="!py-1.5 !px-3 text-sm">
            ← Back
          </Button>
          <div>
            <h3 className="text-xl font-bold text-white flex items-center gap-2">
              {selectedDriver}
              {isOwner && <span className="text-xs bg-red-600 px-2 py-0.5 rounded text-white uppercase">You</span>}
            </h3>
            <p className="text-sm text-slate-400">Garage History at {selectedTrack.name}</p>
          </div>
        </div>
      </div>

      <div className="bg-slate-800/50 rounded-xl overflow-hidden border border-slate-700 backdrop-blur-sm">
        <table className="w-full text-left">
          <thead>
             <tr className="bg-slate-900/80 text-slate-400 text-xs uppercase tracking-wider border-b border-slate-700">
              <th className="px-6 py-4 font-bold">Class</th>
              <th className="px-6 py-4 font-bold">Car Model</th>
              <th className="px-6 py-4 font-bold">Time</th>
              <th className="px-6 py-4 font-bold">Gap</th>
              <th className="px-6 py-4 font-bold text-center">Env.</th>
              <th className="px-6 py-4 font-bold text-center">Input</th>
              <th className="px-6 py-4 font-bold text-right">Date Set</th>
              {isOwner && <th className="px-6 py-4 font-bold text-right">Actions</th>}
             </tr>
          </thead>
          <tbody className="divide-y divide-slate-700/50">
             {selectedDriverTimes.map((time, index) => {
               // Calculate gap to their own best time (Level 2 compares to self)
               const bestTime = selectedDriverTimes[0].totalMilliseconds;
               const gap = time.totalMilliseconds - bestTime;
               const gapStr = gap === 0 ? '-' : `+${(gap / 1000).toFixed(3)}`;

               return (
                 <tr key={time.id} className="hover:bg-slate-700/30 transition-colors group">
                    <td className="px-6 py-4">
                       <span className={`text-xs font-bold px-2 py-1 rounded bg-slate-800 border border-slate-600 text-slate-300`}>
                         {getCarClass(time.carId)}
                       </span>
                    </td>
                    <td className="px-6 py-4 text-white font-medium">
                       {getCarName(time.carId)}
                    </td>
                    <td className="px-6 py-4 font-mono text-lg font-bold text-red-400">
                       {formatTime(time)}
                    </td>
                    <td className="px-6 py-4 font-mono text-sm text-slate-500">
                       {gapStr}
                    </td>
                    <td className="px-6 py-4 text-center">
                      {renderConditions(time.conditions, time.trackTemp)}
                    </td>
                    <td className="px-6 py-4 text-center">
                       <div className="flex justify-center items-center text-slate-500">
                          <InputDeviceIcon device={time.inputDevice} />
                       </div>
                    </td>
                    <td className="px-6 py-4 text-right text-slate-500 text-sm">
                        {new Date(time.timestamp).toLocaleDateString()}
                    </td>
                    {isOwner && (
                      <td className="px-6 py-4 text-right">
                        <button
                          onClick={(e) => { e.stopPropagation(); handleRequestDelete(time.id); }}
                          className="text-slate-600 hover:text-red-500 transition-colors p-1"
                          title="Delete lap time"
                        >
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                          </svg>
                        </button>
                      </td>
                    )}
                 </tr>
               )
             })}
          </tbody>
        </table>
      </div>
    </div>
  );
  }

  return (
    <div className="space-y-6">
      {/* Header Area: Track Info & Filters */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 border-b border-slate-700 pb-6">
        <div className="flex items-center gap-4">
          {selectedTrack.imageUrl && (
            <div className="bg-slate-100/5 p-2 rounded-lg border border-slate-700/50">
               <img 
                 src={selectedTrack.imageUrl} 
                 alt={`${selectedTrack.name} Layout`} 
                 className="w-16 h-16 object-contain brightness-0 invert opacity-90" 
               />
            </div>
          )}
          <div>
            <h2 className="text-3xl font-black text-white uppercase tracking-wider italic">
              {selectedTrack.name}
            </h2>
            <div className="flex items-center gap-2 text-slate-400 mt-1">
              <span className="bg-slate-800 px-2 py-0.5 rounded text-xs border border-slate-700">{selectedTrack.country}</span>
              <span className="text-sm">{selectedTrack.length}</span>
            </div>
          </div>
        </div>

        {!selectedDriver && (
          <div className="flex gap-2 flex-wrap">
             {['ALL', 'GT3', 'GT2', 'GT4', 'CUP'].map(cls => (
               <button
                key={cls}
                onClick={() => setFilterClass(cls)}
                className={`px-3 py-1 rounded text-sm font-bold transition-colors ${
                  filterClass === cls 
                    ? 'bg-red-600 text-white' 
                    : 'bg-slate-800 text-slate-400 hover:bg-slate-700'
                }`}
               >
                 {cls}
               </button>
             ))}
          </div>
        )}
      </div>

      {/* View Logic */}
      {selectedDriver ? renderLevel2() : renderLevel1()}

      {/* Sticky User Row (Visible when user scrolled away) */}
      {stickyState && currentUserStats && (
        <div 
          onClick={scrollToUserRow}
          className={`fixed left-0 right-0 lg:left-auto lg:right-auto lg:max-w-7xl mx-auto px-4 lg:px-4 z-40 transition-all duration-300 animate-fade-in cursor-pointer ${
            stickyState === 'top' ? 'top-[140px]' : 'bottom-6'
          }`}
        >
          <div className="bg-slate-900/95 backdrop-blur-md border border-red-500 rounded-lg shadow-2xl p-4 flex items-center justify-between ring-2 ring-red-500/20">
             <div className="flex items-center gap-4">
                <div className="bg-red-600 text-white text-xs font-bold px-2 py-1 rounded uppercase">Your Rank</div>
                <div className="text-2xl font-bold text-white">#{currentUserStats.rank}</div>
                <div className="hidden sm:block h-6 w-px bg-slate-700"></div>
                <div className="hidden sm:block text-slate-300 text-sm truncate max-w-[150px]">
                   {getCarName(currentUserStats.data.carId)}
                </div>
             </div>
             <div className="flex items-center gap-4">
                <div className="font-mono text-xl font-bold text-red-400">
                    {formatTime(currentUserStats.data)}
                </div>
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d={stickyState === 'top' ? "M5 10l7-7m0 0l7 7m-7-7v18" : "M19 14l-7 7m0 0l-7-7m7 7V3"} />
                 </svg>
             </div>
          </div>
        </div>
      )}

      {/* DELETE CONFIRMATION MODAL */}
      {lapToDelete && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-sm animate-fade-in">
          <div className="bg-slate-900 border border-slate-700 rounded-xl shadow-2xl max-w-md w-full p-6 transform transition-all scale-100 animate-fade-in-up">
            <h3 className="text-xl font-bold text-white mb-2">确认删除?</h3>
            <p className="text-slate-400 mb-6">
              您确定要删除这条圈速记录吗？<br/>
              此操作<span className="text-red-500 font-bold">无法撤销</span>。
            </p>
            <div className="flex gap-3 justify-end">
              <Button 
                variant="secondary" 
                onClick={() => setLapToDelete(null)}
                disabled={isDeleting}
              >
                取消
              </Button>
              <Button 
                variant="primary" 
                onClick={confirmDelete}
                isLoading={isDeleting}
                className="bg-red-600 hover:bg-red-700"
              >
                确认删除
              </Button>
            </div>
          </div>
        </div>
      )}

    </div>
  );
};

export default Leaderboard;

import React from 'react';
import { InputDevice } from '../types';

interface InputDeviceIconProps {
  device?: InputDevice;
  className?: string;
}

const InputDeviceIcon: React.FC<InputDeviceIconProps> = ({ device, className = "h-5 w-5" }) => {
  if (device === 'Wheel') {
     // Racing Wheel Icon
     return (
