      .eq('email', email)
      .maybeSingle(); 
    return !!data;
  } else {
    const users: User[] = JSON.parse(localStorage.getItem(LS_USERS_KEY) || '[]');
    return users.some(u => u.email.toLowerCase() === email.toLowerCase());
