            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:border-red-500 focus:outline-none focus:ring-1 focus:ring-red-500"
          >
            {CARS.map(car => (
              <option key={car.id} value={car.id}>
                [{car.class}] {car.brand} {car.name}
              </option>
            ))}
          </select>
        </div>

        {/* Lap Time Inputs */}
        <div>
          <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">圈速成绩</label>
             {isVerified && (
               <span className="text-[10px] text-green-500 bg-green-900/20 px-1.5 rounded border border-green-800/50">已识别</span>
             )}
          </div>
          <div className="flex items-end gap-2">
            <div className="flex-1">
              <Input 
                placeholder="00" 
                value={minutes}
                onChange={(e) => handleManualTimeChange(setMinutes, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="59"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">分</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">:</span>
            <div className="flex-1">
              <Input 
                placeholder="00" 
                value={seconds}
                onChange={(e) => handleManualTimeChange(setSeconds, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="59"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">秒</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">.</span>
            <div className="flex-1">
              <Input 
                placeholder="000" 
                value={millis}
                onChange={(e) => handleManualTimeChange(setMillis, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="999"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">毫秒</span>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">赛道温度 (°C)</label>
              <div className="relative">
                <Input
                  type="number"
                  placeholder="24"
                  value={trackTemp}
                  onChange={(e) => setTrackTemp(e.target.value)}
                  className={isAnalyzing ? 'opacity-50' : ''}
                />
                <span className="absolute right-4 top-3.5 text-slate-500">°C</span>
              </div>
           </div>

           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">输入设备</label>
              <div className="flex flex-col gap-2">
                 <div className="grid grid-cols-3 gap-2">
                    {(['Wheel', 'Gamepad', 'Keyboard'] as InputDevice[]).map((dev) => (
                      <button
                        key={dev}
                        type="button"
                        onClick={() => setInputDevice(dev)}
                        className={`flex flex-col items-center justify-center p-3 rounded-lg border transition-all ${
                          inputDevice === dev
                            ? 'bg-red-600 border-red-500 text-white shadow-lg shadow-red-900/20'
                            : 'bg-slate-900 border-slate-700 text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                        }`}
                        title={dev === 'Wheel' ? '方向盘' : dev === 'Gamepad' ? '手柄' : '键盘'}
                      >
                        <InputDeviceIcon device={dev} className="h-8 w-8" />
                      </button>
                    ))}
                 </div>
              </div>
           </div>
        </div>

        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">赛道状况</label>
          <div className="flex gap-4">
            <button
              type="button"
              onClick={() => setConditions('Dry')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Dry' 
                  ? 'bg-orange-500/20 border-orange-500 text-orange-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              ☀️ 干地
            </button>
            <button
              type="button"
              onClick={() => setConditions('Wet')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Wet' 
                  ? 'bg-blue-500/20 border-blue-500 text-blue-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              🌧️ 湿地
            </button>
          </div>
        </div>

        {error && (
          <div className="bg-yellow-900/50 border border-yellow-500/50 text-yellow-200 px-4 py-3 rounded text-sm font-semibold break-words">
            ⚠️ {error}
          </div>
        )}

        {successMessage && (
           <div className="bg-green-900/50 border border-green-500/50 text-green-200 px-4 py-3 rounded text-sm font-semibold flex items-center gap-2">
             ✅ {successMessage}
           </div>
        )}

        <div className="flex gap-3 pt-4">
          <Button type="button" variant="ghost" onClick={onCancel} className="flex-1" disabled={isSubmitting || isAnalyzing}>
            {isEditing ? '取消编辑' : '返回'}
          </Button>
          <Button type="submit" className="flex-1" disabled={!!successMessage || isSubmitting || isAnalyzing} isLoading={isSubmitting}>
            {isEditing ? '更新成绩' : '提交成绩'}
          </Button>
        </div>
      </form>
    </div>
  );
};

export default SubmitLapForm;

import React, { useState, useRef } from 'react';
import { Track, User, LapTime, InputDevice } from '../types';
import { CARS, TRACKS } from '../constants';
import { submitLapTime, updateLapTime } from '../services/storageService';
import Button from './Button';
import Input from './Input';
import InputDeviceIcon from './InputDeviceIcon';
import Tesseract from 'tesseract.js';

interface SubmitLapFormProps {
  track: Track;
  user: User;
  onSuccess: () => void;
  onCancel: () => void;
  initialData?: LapTime | null;
}

const SubmitLapForm: React.FC<SubmitLapFormProps> = ({ track: initialTrack, user, onSuccess, onCancel, initialData }) => {
  // State initialization
  const [targetTrackId, setTargetTrackId] = useState(initialData?.trackId || initialTrack.id);
  const [carId, setCarId] = useState(initialData?.carId || CARS[0].id);
  const [minutes, setMinutes] = useState(initialData?.minutes.toString() || '');
  const [seconds, setSeconds] = useState(initialData?.seconds.toString() || '');
  const [millis, setMillis] = useState(initialData?.milliseconds.toString() || '');
  const [conditions, setConditions] = useState<'Dry' | 'Wet'>(initialData?.conditions || 'Dry');
  const [trackTemp, setTrackTemp] = useState(initialData?.trackTemp?.toString() || '');
  const [inputDevice, setInputDevice] = useState<InputDevice>(initialData?.inputDevice || 'Wheel');
  const [isVerified, setIsVerified] = useState<boolean>(initialData?.isVerified || false);

  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // OCR Analysis State
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [ocrProgress, setOcrProgress] = useState<string>('');
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const isEditing = !!initialData;

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // 1. Preview
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      setPreviewImage(base64String);
      analyzeScreenshot(base64String); // Auto-start analysis
    };
    reader.readAsDataURL(file);
  };

  const analyzeScreenshot = async (imageSrc: string) => {
    setIsAnalyzing(true);
    setOcrProgress('初始化 OCR 引擎...');
    setError('');

    try {
      const result = await Tesseract.recognize(
        imageSrc,
        'eng', // English model is sufficient for numbers and basic text
        {
          logger: m => {
            if (m.status === 'recognizing text') {
              setOcrProgress(`正在读取文字: ${(m.progress * 100).toFixed(0)}%`);
            } else {
              setOcrProgress(m.status);
            }
          }
        }
      );

      const text = result.data.text;
      console.log("OCR Raw Text:", text);

      // --- Regex Strategies for Lap Time ---
      // Matches formats like: 1:47.320, 1.47.320, 1:47:320
      // Regex explanation:
      // \b([0-9]{1,2}) -> Group 1: Minutes (1 or 2 digits)
      // [:.;,] -> Separator (colon, dot, semicolon, comma - common OCR errors)
      // ([0-5][0-9]) -> Group 2: Seconds (00-59)
      // [:.;,] -> Separator
      // (\d{2,3})\b -> Group 3: Milliseconds (2 or 3 digits)
      const timeRegex = /\b([0-9]{1,2})[:.;,]([0-5][0-9])[:.;,](\d{2,3})\b/g;

      const matches = [...text.matchAll(timeRegex)];

      if (matches.length > 0) {
        // Parse ALL valid matches into objects
        const candidates = matches.map(match => {
            const m = parseInt(match[1]);
            const s = parseInt(match[2]);
            let msStr = match[3];
            // Pad milliseconds if OCR missed a digit (e.g. read .32 as 320ms, standard ACC format is 3 digits)
            if (msStr.length === 2) msStr += "0"; 
            const ms = parseInt(msStr);
            const total = (m * 60 * 1000) + (s * 1000) + ms;
            return { m, s, ms, total, raw: match[0] };
        }).filter(c => {
             // Filter Noise: 
             // 1. Lap times usually > 30 seconds (excludes sector times or glitches)
             // 2. Lap times usually < 15 minutes (excludes timestamp errors, unless Nordschleife 24h?)
             // Let's set a safe range: 30s to 20min
             return c.total > 30000 && c.total < 1200000;
        });

        if (candidates.length > 0) {
            // Sort by Total Milliseconds (Ascending) -> Fastest time first
            candidates.sort((a, b) => a.total - b.total);

            const bestLap = candidates[0]; // The winner

            console.log("Found valid laps:", candidates);
            console.log("Best lap selected:", bestLap);

            setMinutes(bestLap.m.toString());
            setSeconds(bestLap.s.toString());
            setMillis(bestLap.ms.toString());
            setIsVerified(true); 

            if (candidates.length > 1) {
                setSuccessMessage(`共识别到 ${candidates.length} 个时间，已自动填入最快圈速！`);
            } else {
                setSuccessMessage("成功提取圈速时间！");
            }
        } else {
             throw new Error("识别到了数字，但看起来不像有效的圈速成绩。");
        }
      } else {
        throw new Error("未能在图片中找到类似 '1:45.123' 格式的圈速时间。");
      }

      // --- Attempt to fuzzy match Track Name (Optional/Hard via OCR) ---
      const lowerText = text.toLowerCase();
      const foundTrack = TRACKS.find(t => lowerText.includes(t.name.toLowerCase()) || lowerText.includes(t.id));
      if (foundTrack) {
        setTargetTrackId(foundTrack.id);
      }

      // --- Attempt to fuzzy match Temp ---
      const tempRegex = /(\d{1,2})\s?°?C/i;
      const tempMatch = text.match(tempRegex);
      if (tempMatch) {
         setTrackTemp(tempMatch[1]);
      }

    } catch (err: any) {
      console.error("OCR Analysis Failed:", err);
      setError("OCR 识别失败: " + (err.message || "无法读取文字"));
      setIsVerified(false);
    } finally {
      setIsAnalyzing(false);
      setOcrProgress('');
      // Clear success message after a few seconds
      setTimeout(() => setSuccessMessage(''), 4000);
    }
  };

  const handleManualTimeChange = (setter: React.Dispatch<React.SetStateAction<string>>, value: string) => {
    setter(value);
    // If user manually changes the time, invalidate the verification
    setIsVerified(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMessage('');
    setIsSubmitting(true);

    const m = parseInt(minutes);
    const s = parseInt(seconds);
    const ms = parseInt(millis);
    const tTemp = trackTemp ? parseInt(trackTemp) : undefined;

    if (isNaN(m) || isNaN(s) || isNaN(ms)) {
      setError('请输入有效的圈速。');
      setIsSubmitting(false);
      return;
    }
    if (s >= 60) {
      setError('秒数必须小于60。');
      setIsSubmitting(false);
      return;
    }
    if (ms >= 1000) {
      setError('毫秒数必须小于1000。');
      setIsSubmitting(false);
      return;
    }

    const totalMilliseconds = (m * 60 * 1000) + (s * 1000) + ms;

    const generateId = () => {
      if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
      }
      return Date.now().toString(36) + Math.random().toString(36).substr(2);
    };

    const lapData: LapTime = {
      id: initialData?.id || generateId(), // Preserve ID if editing
      username: user.username,
      userEmail: user.email, 
      trackId: targetTrackId, 
      carId,
      minutes: m,
      seconds: s,
      milliseconds: ms,
      totalMilliseconds,
      timestamp: initialData?.timestamp || new Date().toISOString(), // Preserve timestamp if editing, or use current
      conditions,
      trackTemp: tTemp,
      inputDevice,
      isVerified: isVerified
    };

    let result;
    if (isEditing) {
       // If editing, force update regardless of PB check (assumes correction)
       result = await updateLapTime(lapData);
    } else {
       // If new, use standard submission (checks PB)
       result = await submitLapTime(lapData);
    }

    if (result.success) {
      setSuccessMessage(result.message);
      setTimeout(() => {
        onSuccess();
      }, 1500);
    } else {
      setError(result.message);
    }
    setIsSubmitting(false);
  };

  const currentTrack = TRACKS.find(t => t.id === targetTrackId) || initialTrack;

  return (
    <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-2xl max-w-lg mx-auto w-full animate-fade-in-up">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold text-white flex items-center gap-2">
          <span className="text-red-500">{isEditing ? '编辑圈速' : '录入圈速'}</span>
        </h2>
        <div className="flex items-center gap-2">
          {isVerified && (
             <div className="flex items-center gap-1 text-xs bg-green-900/40 text-green-400 px-2 py-1 rounded border border-green-800">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M6.267 3.455a3.066 3.066 0 001.745-.723 3.066 3.066 0 013.976 0 3.066 3.066 0 001.745.723 3.066 3.066 0 012.812 2.812c.051.643.304 1.254.723 1.745a3.066 3.066 0 010 3.976 3.066 3.066 0 00-.723 1.745 3.066 3.066 0 01-2.812 2.812 3.066 3.066 0 00-1.745.723 3.066 3.066 0 01-3.976 0 3.066 3.066 0 00-1.745-.723 3.066 3.066 0 01-2.812-2.812 3.066 3.066 0 00-.723-1.745 3.066 3.066 0 010-3.976 3.066 3.066 0 00.723-1.745 3.066 3.066 0 012.812-2.812zm7.44 5.252a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
               </svg>
               OCR 已读取
             </div>
          )}
          <div className="text-xs bg-slate-900 px-3 py-1 rounded-full border border-slate-700 text-slate-400">
             {isEditing ? '编辑模式' : '智能识别模式 (OCR)'}
          </div>
        </div>
      </div>

      {/* OCR Upload Section */}
      <div className="mb-6 p-4 bg-slate-900/50 rounded-lg border border-slate-700 border-dashed hover:border-red-500/50 transition-colors">
        <input 
          type="file" 
          accept="image/*" 
          className="hidden" 
          ref={fileInputRef}
          onChange={handleImageUpload}
        />

        {!previewImage ? (
          <button 
            type="button"
            onClick={() => fileInputRef.current?.click()}
            className="w-full flex flex-col items-center justify-center gap-2 py-4 text-slate-400 hover:text-white transition-colors"
          >
            <div className="bg-slate-800 p-3 rounded-full animate-bounce">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
            </div>
            <span className="text-sm font-bold">
              {isEditing ? '上传新截图以更新数据' : '点击上传游戏截图'}
            </span>
            <span className="text-xs text-slate-500 text-center max-w-xs">
               本地 OCR 自动识别 (无上传)。<br/>自动选取图片中最快圈速。
            </span>
          </button>
        ) : (
          <div className="relative">
            <img 
              src={previewImage} 
              alt="Preview" 
              className="w-full h-32 object-cover rounded-lg opacity-80" 
            />
            {isAnalyzing && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/80 backdrop-blur-sm rounded-lg px-4 text-center">
                 <span className="w-8 h-8 border-4 border-red-500 border-t-transparent rounded-full animate-spin mb-2"></span>
                 <span className="text-white font-bold text-sm shadow-black drop-shadow-md">{ocrProgress}</span>
                 <span className="text-xs text-slate-400 mt-1">首次运行可能需要下载语言包</span>
              </div>
            )}
            {!isAnalyzing && (
              <button 
                type="button"
                onClick={() => {
                  setPreviewImage(null);
                  if (!isEditing) {
                      setMinutes('');
                      setSeconds('');
                      setMillis('');
                      setTrackTemp('');
                  }
                  setIsVerified(false);
                }}
                className="absolute top-2 right-2 bg-black/50 text-white rounded-full p-1 hover:bg-red-600 transition-colors"
                title="清除并重新上传"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                </svg>
              </button>
            )}
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Track Selection - Now Editable because OCR likely won't catch it */}
        <div>
           <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">赛道</label>
           </div>
           <select 
             value={targetTrackId} 
             onChange={(e) => setTargetTrackId(e.target.value)}
             className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:border-red-500 focus:outline-none focus:ring-1 focus:ring-red-500"
           >
             {TRACKS.map(t => (
               <option key={t.id} value={t.id}>{t.name}</option>
             ))}
           </select>
        </div>

        {/* Car Selection */}
        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">车辆</label>
          <select 
            value={carId} 
            onChange={(e) => setCarId(e.target.value)}
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:border-red-500 focus:outline-none focus:ring-1 focus:ring-red-500"
          >
            {CARS.map(car => (
              <option key={car.id} value={car.id}>
                [{car.class}] {car.brand} {car.name}
              </option>
            ))}
          </select>
        </div>

        {/* Lap Time Inputs */}
        <div>
          <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">圈速成绩</label>
             {isVerified && (
               <span className="text-[10px] text-green-500 bg-green-900/20 px-1.5 rounded border border-green-800/50">已识别</span>
             )}
          </div>
          <div className="flex items-end gap-2">
            <div className="flex-1">
              <Input 
                placeholder="00" 
                value={minutes}
                onChange={(e) => handleManualTimeChange(setMinutes, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="59"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">分</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">:</span>
            <div className="flex-1">
              <Input 
                placeholder="00" 
                value={seconds}
                onChange={(e) => handleManualTimeChange(setSeconds, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="59"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">秒</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">.</span>
            <div className="flex-1">
              <Input 
                placeholder="000" 
                value={millis}
                onChange={(e) => handleManualTimeChange(setMillis, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="999"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">毫秒</span>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">赛道温度 (°C)</label>
              <div className="relative">
                <Input
                  type="number"
                  placeholder="24"
                  value={trackTemp}
                  onChange={(e) => setTrackTemp(e.target.value)}
                  className={isAnalyzing ? 'opacity-50' : ''}
                />
                <span className="absolute right-4 top-3.5 text-slate-500">°C</span>
              </div>
           </div>

           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">输入设备</label>
              <div className="flex flex-col gap-2">
                 <div className="grid grid-cols-3 gap-2">
                    {(['Wheel', 'Gamepad', 'Keyboard'] as InputDevice[]).map((dev) => (
                      <button
                        key={dev}
                        type="button"
                        onClick={() => setInputDevice(dev)}
                        className={`flex flex-col items-center justify-center p-3 rounded-lg border transition-all ${
                          inputDevice === dev
                            ? 'bg-red-600 border-red-500 text-white shadow-lg shadow-red-900/20'
                            : 'bg-slate-900 border-slate-700 text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                        }`}
                        title={dev === 'Wheel' ? '方向盘' : dev === 'Gamepad' ? '手柄' : '键盘'}
                      >
                        <InputDeviceIcon device={dev} className="h-8 w-8" />
                      </button>
                    ))}
                 </div>
              </div>
           </div>
        </div>

        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">赛道状况</label>
          <div className="flex gap-4">
            <button
              type="button"
              onClick={() => setConditions('Dry')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Dry' 
                  ? 'bg-orange-500/20 border-orange-500 text-orange-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              ☀️ 干地
            </button>
            <button
              type="button"
              onClick={() => setConditions('Wet')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Wet' 
                  ? 'bg-blue-500/20 border-blue-500 text-blue-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              🌧️ 湿地
            </button>
          </div>
        </div>

        {error && (
          <div className="bg-yellow-900/50 border border-yellow-500/50 text-yellow-200 px-4 py-3 rounded text-sm font-semibold break-words">
            ⚠️ {error}
          </div>
        )}

        {successMessage && (
           <div className="bg-green-900/50 border border-green-500/50 text-green-200 px-4 py-3 rounded text-sm font-semibold flex items-center gap-2">
             ✅ {successMessage}
           </div>
        )}

        <div className="flex gap-3 pt-4">
          <Button type="button" variant="ghost" onClick={onCancel} className="flex-1" disabled={isSubmitting || isAnalyzing}>
            {isEditing ? '取消编辑' : '返回'}
          </Button>
          <Button type="submit" className="flex-1" disabled={!!successMessage || isSubmitting || isAnalyzing} isLoading={isSubmitting}>
            {isEditing ? '更新成绩' : '提交成绩'}
          </Button>
        </div>
      </form>
    </div>
  );
};

export default SubmitLapForm;

import React, { useState, useRef } from 'react';
import { Track, User, LapTime, InputDevice } from '../types';
import { CARS, TRACKS } from '../constants';
import { submitLapTime, updateLapTime } from '../services/storageService';
import Button from './Button';
import Input from './Input';
import InputDeviceIcon from './InputDeviceIcon';
import Tesseract from 'tesseract.js';

interface SubmitLapFormProps {
  track: Track;
  user: User;
  onSuccess: () => void;
  onCancel: () => void;
  initialData?: LapTime | null;
}

const SubmitLapForm: React.FC<SubmitLapFormProps> = ({ track: initialTrack, user, onSuccess, onCancel, initialData }) => {
  // State initialization
  const [targetTrackId, setTargetTrackId] = useState(initialData?.trackId || initialTrack.id);
  const [carId, setCarId] = useState(initialData?.carId || CARS[0].id);
  const [minutes, setMinutes] = useState(initialData?.minutes.toString() || '');
  const [seconds, setSeconds] = useState(initialData?.seconds.toString() || '');
  const [millis, setMillis] = useState(initialData?.milliseconds.toString() || '');
  const [conditions, setConditions] = useState<'Dry' | 'Wet'>(initialData?.conditions || 'Dry');
  const [trackTemp, setTrackTemp] = useState(initialData?.trackTemp?.toString() || '');
  const [inputDevice, setInputDevice] = useState<InputDevice>(initialData?.inputDevice || 'Wheel');
  const [isVerified, setIsVerified] = useState<boolean>(initialData?.isVerified || false);

  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // OCR Analysis State
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [ocrProgress, setOcrProgress] = useState<string>('');
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const isEditing = !!initialData;

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // 1. Preview
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      setPreviewImage(base64String);
      analyzeScreenshot(base64String); // Auto-start analysis
    };
    reader.readAsDataURL(file);
  };

  // --- Helper: Fuzzy Match Scorer ---
  // Returns a score (number of matched keywords)
  const calculateMatchScore = (sourceText: string, targetName: string) => {
    const text = sourceText.toLowerCase();
    // Split target name into key tokens (e.g. "Ferrari 296 GT3" -> ["ferrari", "296", "gt3"])
    // Filter out generic words like "GT3" if you want, but usually it helps confirm the class.
    const tokens = targetName.toLowerCase().split(/[\s\-_()]+/).filter(t => t.length > 2);

    let score = 0;
    tokens.forEach(token => {
      if (text.includes(token)) {
        // Bonus for specific unique numbers (like 296, 720s, 992)
        if (/\d/.test(token)) score += 2;
        else score += 1;
      }
    });
    return score;
  };

  const analyzeScreenshot = async (imageSrc: string) => {
    setIsAnalyzing(true);
    setOcrProgress('初始化 OCR 引擎...');
    setError('');

    try {
      const result = await Tesseract.recognize(
        imageSrc,
        'eng', 
        {
          logger: m => {
            if (m.status === 'recognizing text') {
              setOcrProgress(`正在读取文字: ${(m.progress * 100).toFixed(0)}%`);
            } else {
              setOcrProgress(m.status);
            }
          }
        }
      );

      const text = result.data.text;
      console.log("OCR Raw Text:", text);
      const lowerText = text.toLowerCase();

      let identifiedInfo: string[] = [];

      // 1. TRACK RECOGNITION (Keyword Scoring)
      let bestTrackId = initialTrack.id; // Default to current
      let bestTrackScore = 0;

      TRACKS.forEach(t => {
        // Use Track Name and ID as keywords
        const score = calculateMatchScore(text, t.name) + (lowerText.includes(t.id) ? 2 : 0);
        if (score > bestTrackScore) {
          bestTrackScore = score;
          bestTrackId = t.id;
        }
      });

      // Threshold: at least 1 strong keyword match to switch track
      if (bestTrackScore > 0 && bestTrackId !== targetTrackId) {
        setTargetTrackId(bestTrackId);
        const tName = TRACKS.find(t => t.id === bestTrackId)?.name;
        identifiedInfo.push(`赛道: ${tName}`);
      }

      // 2. CAR RECOGNITION (Keyword Scoring)
      let bestCarId = carId;
      let bestCarScore = 0;

      CARS.forEach(c => {
        // Combine Brand and Name for matching (e.g. "Porsche 992 GT3 R")
        const fullName = `${c.brand} ${c.name}`;
        const score = calculateMatchScore(text, fullName);

        if (score > bestCarScore) {
          bestCarScore = score;
          bestCarId = c.id;
        }
      });

      // Threshold: Car names are complex, need a decent score (e.g. matched "Ferrari" and "296")
      if (bestCarScore >= 2) {
         setCarId(bestCarId);
         const cName = CARS.find(c => c.id === bestCarId)?.name;
         identifiedInfo.push(`车型: ${cName}`);
      }

      // 3. LAP TIME RECOGNITION (Existing Logic)
      const timeRegex = /\b([0-9]{1,2})[:.;,]([0-5][0-9])[:.;,](\d{2,3})\b/g;
      const matches = [...text.matchAll(timeRegex)];
      let foundTime = false;

      if (matches.length > 0) {
        const candidates = matches.map(match => {
            const m = parseInt(match[1]);
            const s = parseInt(match[2]);
            let msStr = match[3];
            if (msStr.length === 2) msStr += "0"; 
            const ms = parseInt(msStr);
            const total = (m * 60 * 1000) + (s * 1000) + ms;
            return { m, s, ms, total, raw: match[0] };
        }).filter(c => c.total > 30000 && c.total < 1200000);

        if (candidates.length > 0) {
            candidates.sort((a, b) => a.total - b.total);
            const bestLap = candidates[0];

            setMinutes(bestLap.m.toString());
            setSeconds(bestLap.s.toString());
            setMillis(bestLap.ms.toString());
            foundTime = true;
            identifiedInfo.push(`圈速: ${bestLap.m}:${bestLap.s}.${bestLap.ms}`);
        }
      }

      // 4. TEMP RECOGNITION
      const tempRegex = /(\d{1,2})\s?°?C/i;
      const tempMatch = text.match(tempRegex);
      if (tempMatch) {
         setTrackTemp(tempMatch[1]);
         identifiedInfo.push(`温度: ${tempMatch[1]}°C`);
      }

      // FINAL FEEDBACK
      if (foundTime) {
        setIsVerified(true);
        const summary = identifiedInfo.length > 0 
           ? `识别成功: ${identifiedInfo.join(', ')}` 
           : "成功提取圈速时间！";
        setSuccessMessage(summary);
      } else {
        throw new Error("未能识别有效的圈速时间，请确保截图包含 '分:秒.毫秒' 格式。");
      }

    } catch (err: any) {
      console.error("OCR Analysis Failed:", err);
      setError("OCR 识别失败: " + (err.message || "无法读取文字"));
      setIsVerified(false);
    } finally {
      setIsAnalyzing(false);
      setOcrProgress('');
      setTimeout(() => setSuccessMessage(''), 5000); // Show longer success message
    }
  };

  const handleManualTimeChange = (setter: React.Dispatch<React.SetStateAction<string>>, value: string) => {
    setter(value);
    // If user manually changes the time, invalidate the verification
    setIsVerified(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMessage('');
    setIsSubmitting(true);

    const m = parseInt(minutes);
    const s = parseInt(seconds);
    const ms = parseInt(millis);
    const tTemp = trackTemp ? parseInt(trackTemp) : undefined;

    if (isNaN(m) || isNaN(s) || isNaN(ms)) {
      setError('请输入有效的圈速。');
      setIsSubmitting(false);
      return;
    }
    if (s >= 60) {
      setError('秒数必须小于60。');
      setIsSubmitting(false);
      return;
    }
    if (ms >= 1000) {
      setError('毫秒数必须小于1000。');
      setIsSubmitting(false);
      return;
    }

    const totalMilliseconds = (m * 60 * 1000) + (s * 1000) + ms;

    const generateId = () => {
      if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
      }
      return Date.now().toString(36) + Math.random().toString(36).substr(2);
    };

    const lapData: LapTime = {
      id: initialData?.id || generateId(), // Preserve ID if editing
      username: user.username,
      userEmail: user.email, 
      trackId: targetTrackId, 
      carId,
      minutes: m,
      seconds: s,
      milliseconds: ms,
      totalMilliseconds,
      timestamp: initialData?.timestamp || new Date().toISOString(), // Preserve timestamp if editing, or use current
      conditions,
      trackTemp: tTemp,
      inputDevice,
      isVerified: isVerified
    };

    let result;
    if (isEditing) {
       // If editing, force update regardless of PB check (assumes correction)
       result = await updateLapTime(lapData);
    } else {
       // If new, use standard submission (checks PB)
       result = await submitLapTime(lapData);
    }

    if (result.success) {
      setSuccessMessage(result.message);
      setTimeout(() => {
        onSuccess();
      }, 1500);
    } else {
      setError(result.message);
    }
    setIsSubmitting(false);
  };

  const currentTrack = TRACKS.find(t => t.id === targetTrackId) || initialTrack;

  return (
    <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-2xl max-w-lg mx-auto w-full animate-fade-in-up">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold text-white flex items-center gap-2">
          <span className="text-red-500">{isEditing ? '编辑圈速' : '录入圈速'}</span>
        </h2>
        <div className="flex items-center gap-2">
          {isVerified && (
             <div className="flex items-center gap-1 text-xs bg-green-900/40 text-green-400 px-2 py-1 rounded border border-green-800">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M6.267 3.455a3.066 3.066 0 001.745-.723 3.066 3.066 0 013.976 0 3.066 3.066 0 001.745.723 3.066 3.066 0 012.812 2.812c.051.643.304 1.254.723 1.745a3.066 3.066 0 010 3.976 3.066 3.066 0 00-.723 1.745 3.066 3.066 0 01-2.812 2.812 3.066 3.066 0 00-1.745.723 3.066 3.066 0 01-3.976 0 3.066 3.066 0 00-1.745-.723 3.066 3.066 0 01-2.812-2.812 3.066 3.066 0 00-.723-1.745 3.066 3.066 0 010-3.976 3.066 3.066 0 00.723-1.745 3.066 3.066 0 012.812-2.812zm7.44 5.252a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
               </svg>
               OCR 已读取
             </div>
          )}
          <div className="text-xs bg-slate-900 px-3 py-1 rounded-full border border-slate-700 text-slate-400">
             {isEditing ? '编辑模式' : '智能识别模式 (OCR)'}
          </div>
        </div>
      </div>

      {/* OCR Upload Section */}
      <div className="mb-6 p-4 bg-slate-900/50 rounded-lg border border-slate-700 border-dashed hover:border-red-500/50 transition-colors">
        <input 
          type="file" 
          accept="image/*" 
          className="hidden" 
          ref={fileInputRef}
          onChange={handleImageUpload}
        />

        {!previewImage ? (
          <button 
            type="button"
            onClick={() => fileInputRef.current?.click()}
            className="w-full flex flex-col items-center justify-center gap-2 py-4 text-slate-400 hover:text-white transition-colors"
          >
            <div className="bg-slate-800 p-3 rounded-full animate-bounce">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
            </div>
            <span className="text-sm font-bold">
              {isEditing ? '上传新截图以更新数据' : '点击上传游戏截图'}
            </span>
            <span className="text-xs text-slate-500 text-center max-w-xs">
               本地 OCR 自动识别 (无上传)。<br/>自动识别圈速、车型和赛道。
            </span>
          </button>
        ) : (
          <div className="relative">
            <img 
              src={previewImage} 
              alt="Preview" 
              className="w-full h-32 object-cover rounded-lg opacity-80" 
            />
            {isAnalyzing && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/80 backdrop-blur-sm rounded-lg px-4 text-center">
                 <span className="w-8 h-8 border-4 border-red-500 border-t-transparent rounded-full animate-spin mb-2"></span>
                 <span className="text-white font-bold text-sm shadow-black drop-shadow-md">{ocrProgress}</span>
                 <span className="text-xs text-slate-400 mt-1">分析文本特征中...</span>
              </div>
            )}
            {!isAnalyzing && (
              <button 
                type="button"
                onClick={() => {
                  setPreviewImage(null);
                  if (!isEditing) {
                      setMinutes('');
                      setSeconds('');
                      setMillis('');
                      setTrackTemp('');
                      setTargetTrackId(initialTrack.id); // Reset track
                  }
                  setIsVerified(false);
                }}
                className="absolute top-2 right-2 bg-black/50 text-white rounded-full p-1 hover:bg-red-600 transition-colors"
                title="清除并重新上传"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                </svg>
              </button>
            )}
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Track Selection */}
        <div>
           <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">赛道</label>
             {isVerified && targetTrackId !== initialTrack.id && (
               <span className="text-[10px] text-green-500 bg-green-900/20 px-1.5 rounded border border-green-800/50 animate-pulse">
                 OCR 自动选择
               </span>
             )}
           </div>
           <select 
             value={targetTrackId} 
             onChange={(e) => setTargetTrackId(e.target.value)}
             className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:border-red-500 focus:outline-none focus:ring-1 focus:ring-red-500"
           >
             {TRACKS.map(t => (
               <option key={t.id} value={t.id}>{t.name}</option>
             ))}
           </select>
        </div>

        {/* Car Selection */}
        <div>
          <div className="flex items-center gap-2 mb-2">
            <label className="block text-slate-400 text-sm font-bold">车辆</label>
             {isVerified && carId !== CARS[0].id && (
               <span className="text-[10px] text-green-500 bg-green-900/20 px-1.5 rounded border border-green-800/50 animate-pulse">
                 OCR 自动选择
               </span>
             )}
          </div>
          <select 
            value={carId} 
            onChange={(e) => setCarId(e.target.value)}
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:border-red-500 focus:outline-none focus:ring-1 focus:ring-red-500"
          >
            {CARS.map(car => (
              <option key={car.id} value={car.id}>
                [{car.class}] {car.brand} {car.name}
              </option>
            ))}
          </select>
        </div>

        {/* Lap Time Inputs */}
        <div>
          <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">圈速成绩</label>
             {isVerified && (
               <span className="text-[10px] text-green-500 bg-green-900/20 px-1.5 rounded border border-green-800/50">已识别</span>
             )}
          </div>
          <div className="flex items-end gap-2">
            <div className="flex-1">
              <Input 
                placeholder="00" 
                value={minutes}
                onChange={(e) => handleManualTimeChange(setMinutes, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="59"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">分</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">:</span>
            <div className="flex-1">
              <Input 
                placeholder="00" 
                value={seconds}
                onChange={(e) => handleManualTimeChange(setSeconds, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="59"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">秒</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">.</span>
            <div className="flex-1">
              <Input 
                placeholder="000" 
                value={millis}
                onChange={(e) => handleManualTimeChange(setMillis, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="999"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">毫秒</span>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">赛道温度 (°C)</label>
              <div className="relative">
                <Input
                  type="number"
                  placeholder="24"
                  value={trackTemp}
                  onChange={(e) => setTrackTemp(e.target.value)}
                  className={isAnalyzing ? 'opacity-50' : ''}
                />
                <span className="absolute right-4 top-3.5 text-slate-500">°C</span>
              </div>
           </div>

           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">输入设备</label>
              <div className="flex flex-col gap-2">
                 <div className="grid grid-cols-3 gap-2">
                    {(['Wheel', 'Gamepad', 'Keyboard'] as InputDevice[]).map((dev) => (
                      <button
                        key={dev}
                        type="button"
                        onClick={() => setInputDevice(dev)}
                        className={`flex flex-col items-center justify-center p-3 rounded-lg border transition-all ${
                          inputDevice === dev
                            ? 'bg-red-600 border-red-500 text-white shadow-lg shadow-red-900/20'
                            : 'bg-slate-900 border-slate-700 text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                        }`}
                        title={dev === 'Wheel' ? '方向盘' : dev === 'Gamepad' ? '手柄' : '键盘'}
                      >
                        <InputDeviceIcon device={dev} className="h-8 w-8" />
                      </button>
                    ))}
                 </div>
              </div>
           </div>
        </div>

        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">赛道状况</label>
          <div className="flex gap-4">
            <button
              type="button"
              onClick={() => setConditions('Dry')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Dry' 
                  ? 'bg-orange-500/20 border-orange-500 text-orange-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              ☀️ 干地
            </button>
            <button
              type="button"
              onClick={() => setConditions('Wet')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Wet' 
                  ? 'bg-blue-500/20 border-blue-500 text-blue-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              🌧️ 湿地
            </button>
          </div>
        </div>

        {error && (
          <div className="bg-yellow-900/50 border border-yellow-500/50 text-yellow-200 px-4 py-3 rounded text-sm font-semibold break-words">
            ⚠️ {error}
          </div>
        )}

        {successMessage && (
           <div className="bg-green-900/50 border border-green-500/50 text-green-200 px-4 py-3 rounded text-sm font-semibold flex items-center gap-2">
             ✅ {successMessage}
           </div>
        )}

        <div className="flex gap-3 pt-4">
          <Button type="button" variant="ghost" onClick={onCancel} className="flex-1" disabled={isSubmitting || isAnalyzing}>
            {isEditing ? '取消编辑' : '返回'}
          </Button>
          <Button type="submit" className="flex-1" disabled={!!successMessage || isSubmitting || isAnalyzing} isLoading={isSubmitting}>
            {isEditing ? '更新成绩' : '提交成绩'}
          </Button>
        </div>
      </form>
    </div>
  );
};

export default SubmitLapForm;

import React, { useState, useRef, useEffect } from 'react';
import { Track, User, LapTime, InputDevice } from '../types';
import { CARS, TRACKS } from '../constants';
import { submitLapTime, updateLapTime } from '../services/storageService';
import Button from './Button';
import Input from './Input';
import InputDeviceIcon from './InputDeviceIcon';
import Tesseract from 'tesseract.js';

interface SubmitLapFormProps {
  track: Track;
  user: User;
  onSuccess: () => void;
  onCancel: () => void;
  initialData?: LapTime | null;
}

interface CropBox {
  x: number;
  y: number;
  width: number;
  height: number;
}

const SubmitLapForm: React.FC<SubmitLapFormProps> = ({ track: initialTrack, user, onSuccess, onCancel, initialData }) => {
  // State initialization
  const [targetTrackId, setTargetTrackId] = useState(initialData?.trackId || initialTrack.id);
  const [carId, setCarId] = useState(initialData?.carId || CARS[0].id);
  const [minutes, setMinutes] = useState(initialData?.minutes.toString() || '');
  const [seconds, setSeconds] = useState(initialData?.seconds.toString() || '');
  const [millis, setMillis] = useState(initialData?.milliseconds.toString() || '');
  const [conditions, setConditions] = useState<'Dry' | 'Wet'>(initialData?.conditions || 'Dry');
  const [trackTemp, setTrackTemp] = useState(initialData?.trackTemp?.toString() || '');
  const [inputDevice, setInputDevice] = useState<InputDevice>(initialData?.inputDevice || 'Wheel');
  const [isVerified, setIsVerified] = useState<boolean>(initialData?.isVerified || false);

  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // OCR & Cropping State
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [ocrProgress, setOcrProgress] = useState<string>('');
  const [previewImage, setPreviewImage] = useState<string | null>(null);

  // Cropping logic
  const [isDragging, setIsDragging] = useState(false);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });
  const [cropBox, setCropBox] = useState<CropBox | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const imgRef = useRef<HTMLImageElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const isEditing = !!initialData;

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      setPreviewImage(base64String);
      setCropBox(null); // Reset crop on new image
      // Note: We don't auto-analyze anymore, we wait for user to crop or click
    };
    reader.readAsDataURL(file);
  };

  // --- MOUSE EVENTS FOR CROPPING ---

  const getRelativeCoords = (e: React.MouseEvent) => {
    if (!containerRef.current) return { x: 0, y: 0 };
    const rect = containerRef.current.getBoundingClientRect();
    return {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top
    };
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if (!previewImage || isAnalyzing) return;
    const coords = getRelativeCoords(e);
    setIsDragging(true);
    setStartPos(coords);
    setCropBox({ x: coords.x, y: coords.y, width: 0, height: 0 });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging) return;
    const current = getRelativeCoords(e);

    const width = current.x - startPos.x;
    const height = current.y - startPos.y;

    // Allow dragging in any direction (calculate top-left)
    setCropBox({
      x: width > 0 ? startPos.x : current.x,
      y: height > 0 ? startPos.y : current.y,
      width: Math.abs(width),
      height: Math.abs(height)
    });
  };

  const handleMouseUp = () => {
    setIsDragging(false);
    // If box is too small (accidental click), clear it
    if (cropBox && (cropBox.width < 10 || cropBox.height < 10)) {
      setCropBox(null);
    }
  };

  // --- CROP IMAGE HELPER ---
  const getCroppedImg = (): string | null => {
    const image = imgRef.current;
    if (!image || !cropBox) return previewImage; // Fallback to full image

    const canvas = document.createElement('canvas');
    // Calculate scale factor (Display size vs Natural size)
    const scaleX = image.naturalWidth / image.width;
    const scaleY = image.naturalHeight / image.height;

    canvas.width = cropBox.width * scaleX;
    canvas.height = cropBox.height * scaleY;

    const ctx = canvas.getContext('2d');
    if (!ctx) return null;

    ctx.drawImage(
      image,
      cropBox.x * scaleX,    // Source X
      cropBox.y * scaleY,    // Source Y
      cropBox.width * scaleX, // Source Width
      cropBox.height * scaleY,// Source Height
      0, 0,                  // Dest X, Y
      canvas.width,          // Dest Width
      canvas.height          // Dest Height
    );

    return canvas.toDataURL('image/jpeg');
  };

  // --- Helper: Fuzzy Match Scorer ---
  const calculateMatchScore = (sourceText: string, targetName: string) => {
    const text = sourceText.toLowerCase();
    const tokens = targetName.toLowerCase().split(/[\s\-_()]+/).filter(t => t.length > 2);

    let score = 0;
    tokens.forEach(token => {
      if (text.includes(token)) {
        if (/\d/.test(token)) score += 2;
        else score += 1;
      }
    });
    return score;
  };

  const analyzeSelection = async () => {
    const imageToAnalyze = getCroppedImg();
    if (!imageToAnalyze) return;

    setIsAnalyzing(true);
    setOcrProgress('初始化 OCR 引擎...');
    setError('');

    try {
      const result = await Tesseract.recognize(
        imageToAnalyze,
        'eng', 
        {
          logger: m => {
            if (m.status === 'recognizing text') {
              setOcrProgress(`正在读取文字: ${(m.progress * 100).toFixed(0)}%`);
            } else {
              setOcrProgress(m.status);
            }
          }
        }
      );

      const text = result.data.text;
      console.log("OCR Raw Text:", text);
      const lowerText = text.toLowerCase();

      let identifiedInfo: string[] = [];

      // 1. CAR RECOGNITION (Prioritize if cropped, usually accurate)
      let bestCarId = carId;
      let bestCarScore = 0;

      CARS.forEach(c => {
        const fullName = `${c.brand} ${c.name}`;
        const score = calculateMatchScore(text, fullName);
        if (score > bestCarScore) {
          bestCarScore = score;
          bestCarId = c.id;
        }
      });

      // Lower threshold for cropped images because we expect less noise
      if (bestCarScore >= 1) {
         setCarId(bestCarId);
         const cName = CARS.find(c => c.id === bestCarId)?.name;
         identifiedInfo.push(`车型: ${cName}`);
      }

      // 2. LAP TIME RECOGNITION
      const timeRegex = /\b([0-9]{1,2})[:.;,]([0-5][0-9])[:.;,](\d{2,3})\b/g;
      const matches = [...text.matchAll(timeRegex)];
      let foundTime = false;

      if (matches.length > 0) {
        const candidates = matches.map(match => {
            const m = parseInt(match[1]);
            const s = parseInt(match[2]);
            let msStr = match[3];
            if (msStr.length === 2) msStr += "0"; 
            const ms = parseInt(msStr);
            const total = (m * 60 * 1000) + (s * 1000) + ms;
            return { m, s, ms, total, raw: match[0] };
        }).filter(c => c.total > 30000 && c.total < 1200000);

        if (candidates.length > 0) {
            candidates.sort((a, b) => a.total - b.total);
            const bestLap = candidates[0];

            setMinutes(bestLap.m.toString());
            setSeconds(bestLap.s.toString());
            setMillis(bestLap.ms.toString());
            foundTime = true;
            identifiedInfo.push(`圈速: ${bestLap.m}:${bestLap.s}.${bestLap.ms}`);
        }
      }

      // 3. TEMP RECOGNITION (Might not be in the crop row, but try anyway)
      const tempRegex = /(\d{1,2})\s?°?C/i;
      const tempMatch = text.match(tempRegex);
      if (tempMatch) {
         setTrackTemp(tempMatch[1]);
         identifiedInfo.push(`温度: ${tempMatch[1]}°C`);
      }

      // FINAL FEEDBACK
      if (foundTime || bestCarScore >= 1) {
        setIsVerified(true);
        const summary = identifiedInfo.length > 0 
           ? `识别成功: ${identifiedInfo.join(', ')}` 
           : "读取成功！";
        setSuccessMessage(summary);
      } else {
        throw new Error("选区内未识别到明显的圈速或车型信息，请调整框选区域。");
      }

    } catch (err: any) {
      console.error("OCR Analysis Failed:", err);
      setError("识别失败: " + (err.message || "无法读取文字"));
      setIsVerified(false);
    } finally {
      setIsAnalyzing(false);
      setOcrProgress('');
      setTimeout(() => setSuccessMessage(''), 5000);
    }
  };

  const handleManualTimeChange = (setter: React.Dispatch<React.SetStateAction<string>>, value: string) => {
    setter(value);
    setIsVerified(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMessage('');
    setIsSubmitting(true);

    const m = parseInt(minutes);
    const s = parseInt(seconds);
    const ms = parseInt(millis);
    const tTemp = trackTemp ? parseInt(trackTemp) : undefined;

    if (isNaN(m) || isNaN(s) || isNaN(ms)) {
      setError('请输入有效的圈速。');
      setIsSubmitting(false);
      return;
    }
    if (s >= 60) {
      setError('秒数必须小于60。');
      setIsSubmitting(false);
      return;
    }
    if (ms >= 1000) {
      setError('毫秒数必须小于1000。');
      setIsSubmitting(false);
      return;
    }

    const totalMilliseconds = (m * 60 * 1000) + (s * 1000) + ms;

    const generateId = () => {
      if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
      }
      return Date.now().toString(36) + Math.random().toString(36).substr(2);
    };

    const lapData: LapTime = {
      id: initialData?.id || generateId(),
      username: user.username,
      userEmail: user.email, 
      trackId: targetTrackId, 
      carId,
      minutes: m,
      seconds: s,
      milliseconds: ms,
      totalMilliseconds,
      timestamp: initialData?.timestamp || new Date().toISOString(),
      conditions,
      trackTemp: tTemp,
      inputDevice,
      isVerified: isVerified
    };

    let result;
    if (isEditing) {
       result = await updateLapTime(lapData);
    } else {
       result = await submitLapTime(lapData);
    }

    if (result.success) {
      setSuccessMessage(result.message);
      setTimeout(() => {
        onSuccess();
      }, 1500);
    } else {
      setError(result.message);
    }
    setIsSubmitting(false);
  };

  return (
    <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-2xl max-w-lg mx-auto w-full animate-fade-in-up">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold text-white flex items-center gap-2">
          <span className="text-red-500">{isEditing ? '编辑圈速' : '录入圈速'}</span>
        </h2>
        <div className="flex items-center gap-2">
          {isVerified && (
             <div className="flex items-center gap-1 text-xs bg-green-900/40 text-green-400 px-2 py-1 rounded border border-green-800">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M6.267 3.455a3.066 3.066 0 001.745-.723 3.066 3.066 0 013.976 0 3.066 3.066 0 001.745.723 3.066 3.066 0 012.812 2.812c.051.643.304 1.254.723 1.745a3.066 3.066 0 010 3.976 3.066 3.066 0 00-.723 1.745 3.066 3.066 0 01-2.812 2.812 3.066 3.066 0 00-1.745-.723 3.066 3.066 0 01-3.976 0 3.066 3.066 0 00-1.745-.723 3.066 3.066 0 01-2.812-2.812 3.066 3.066 0 00-.723-1.745 3.066 3.066 0 010-3.976 3.066 3.066 0 00.723-1.745 3.066 3.066 0 012.812-2.812zm7.44 5.252a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
               </svg>
               OCR 已读取
             </div>
          )}
          <div className="text-xs bg-slate-900 px-3 py-1 rounded-full border border-slate-700 text-slate-400">
             {isEditing ? '编辑模式' : 'OCR 识别模式'}
          </div>
        </div>
      </div>

      {/* Image Upload & Crop Section */}
      <div className="mb-6">
        <input 
          type="file" 
          accept="image/*" 
          className="hidden" 
          ref={fileInputRef}
          onChange={handleImageUpload}
        />

        {!previewImage ? (
          <button 
            type="button"
            onClick={() => fileInputRef.current?.click()}
            className="w-full flex flex-col items-center justify-center gap-2 py-8 bg-slate-900/50 rounded-lg border border-slate-700 border-dashed hover:border-red-500/50 transition-colors"
          >
            <div className="bg-slate-800 p-3 rounded-full animate-bounce">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
            </div>
            <span className="text-sm font-bold">
              {isEditing ? '上传新截图以更新数据' : '点击上传游戏截图'}
            </span>
            <span className="text-xs text-slate-500 text-center max-w-xs">
               推荐：截图后框选【车型】和【圈速】所在行<br/>以获得最高识别精度。
            </span>
          </button>
        ) : (
          <div className="space-y-4">
            <div className="relative rounded-lg overflow-hidden border border-slate-600 bg-slate-950 select-none group">
               {/* Container for Image + Crop Overlay */}
               <div 
                  ref={containerRef}
                  className="relative cursor-crosshair"
                  onMouseDown={handleMouseDown}
                  onMouseMove={handleMouseMove}
                  onMouseUp={handleMouseUp}
                  onMouseLeave={handleMouseUp}
               >
                 <img 
                    ref={imgRef}
                    src={previewImage} 
                    alt="Preview" 
                    className="w-full object-contain block pointer-events-none" 
                    draggable={false}
                 />

                 {/* Selection Box Overlay */}
                 {cropBox && (
                    <div 
                      className="absolute border-2 border-red-500 bg-red-500/10 shadow-[0_0_0_9999px_rgba(0,0,0,0.5)] pointer-events-none"
                      style={{
                        left: cropBox.x,
                        top: cropBox.y,
                        width: cropBox.width,
                        height: cropBox.height,
                      }}
                    >
                      {/* Helper Text inside selection */}
                      <div className="absolute -top-6 left-0 bg-red-600 text-white text-[10px] px-1 rounded whitespace-nowrap">
                         已选区域
                      </div>
                    </div>
                 )}

                 {/* Hint Overlay when not dragging */}
                 {!cropBox && !isDragging && !isAnalyzing && (
                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none bg-black/30">
                       <span className="bg-black/70 text-white px-3 py-1 rounded text-sm backdrop-blur-sm">
                          请用鼠标框选包含 <b className="text-red-400">车型</b> 和 <b className="text-red-400">圈速</b> 的一行
                       </span>
                    </div>
                 )}

                 {/* Loading Overlay */}
                 {isAnalyzing && (
                  <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/80 backdrop-blur-sm z-10">
                     <span className="w-8 h-8 border-4 border-red-500 border-t-transparent rounded-full animate-spin mb-2"></span>
                     <span className="text-white font-bold text-sm shadow-black drop-shadow-md">{ocrProgress}</span>
                  </div>
                 )}
               </div>

               {/* Clear Button */}
               {!isAnalyzing && (
                 <button 
                  type="button"
                  onClick={() => {
                    setPreviewImage(null);
                    setCropBox(null);
                    setIsVerified(false);
                    if (!isEditing) {
                        setMinutes('');
                        setSeconds('');
                        setMillis('');
                        setTrackTemp('');
                    }
                  }}
                  className="absolute top-2 right-2 bg-black/60 text-white rounded-full p-1.5 hover:bg-red-600 transition-colors z-20"
                  title="重新上传"
                 >
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                     <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                   </svg>
                 </button>
               )}
            </div>

            {/* Action Buttons for Image */}
            <div className="flex gap-2">
               <Button 
                 type="button" 
                 variant={cropBox ? 'primary' : 'secondary'}
                 className="flex-1 py-2"
                 onClick={analyzeSelection}
                 disabled={isAnalyzing}
               >
                 {cropBox ? '识别框选区域' : '识别整张图片'}
               </Button>
            </div>
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Track Selection */}
        <div>
           <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">赛道</label>
             <span className="text-[10px] text-slate-500 ml-auto">请手动选择赛道</span>
           </div>
           <select 
             value={targetTrackId} 
             onChange={(e) => setTargetTrackId(e.target.value)}
             className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:border-red-500 focus:outline-none focus:ring-1 focus:ring-red-500"
           >
             {TRACKS.map(t => (
               <option key={t.id} value={t.id}>{t.name}</option>
             ))}
           </select>
        </div>

        {/* Car Selection */}
        <div>
          <div className="flex items-center gap-2 mb-2">
            <label className="block text-slate-400 text-sm font-bold">车辆</label>
             {isVerified && carId !== CARS[0].id && (
               <span className="text-[10px] text-green-500 bg-green-900/20 px-1.5 rounded border border-green-800/50 animate-pulse">
                 OCR 自动选择
               </span>
             )}
          </div>
          <select 
            value={carId} 
            onChange={(e) => setCarId(e.target.value)}
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:border-red-500 focus:outline-none focus:ring-1 focus:ring-red-500"
          >
            {CARS.map(car => (
              <option key={car.id} value={car.id}>
                [{car.class}] {car.brand} {car.name}
              </option>
            ))}
          </select>
        </div>

        {/* Lap Time Inputs */}
        <div>
          <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">圈速成绩</label>
             {isVerified && (
               <span className="text-[10px] text-green-500 bg-green-900/20 px-1.5 rounded border border-green-800/50">已识别</span>
             )}
          </div>
          <div className="flex items-end gap-2">
            <div className="flex-1">
              <Input 
                placeholder="00" 
                value={minutes}
                onChange={(e) => handleManualTimeChange(setMinutes, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="59"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">分</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">:</span>
            <div className="flex-1">
              <Input 
                placeholder="00" 
                value={seconds}
                onChange={(e) => handleManualTimeChange(setSeconds, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="59"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">秒</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">.</span>
            <div className="flex-1">
              <Input 
                placeholder="000" 
                value={millis}
                onChange={(e) => handleManualTimeChange(setMillis, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="999"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">毫秒</span>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">赛道温度 (°C)</label>
              <div className="relative">
                <Input
                  type="number"
                  placeholder="24"
                  value={trackTemp}
                  onChange={(e) => setTrackTemp(e.target.value)}
                  className={isAnalyzing ? 'opacity-50' : ''}
                />
                <span className="absolute right-4 top-3.5 text-slate-500">°C</span>
              </div>
           </div>

           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">输入设备</label>
              <div className="flex flex-col gap-2">
                 <div className="grid grid-cols-3 gap-2">
                    {(['Wheel', 'Gamepad', 'Keyboard'] as InputDevice[]).map((dev) => (
                      <button
                        key={dev}
                        type="button"
                        onClick={() => setInputDevice(dev)}
                        className={`flex flex-col items-center justify-center p-3 rounded-lg border transition-all ${
                          inputDevice === dev
                            ? 'bg-red-600 border-red-500 text-white shadow-lg shadow-red-900/20'
                            : 'bg-slate-900 border-slate-700 text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                        }`}
                        title={dev === 'Wheel' ? '方向盘' : dev === 'Gamepad' ? '手柄' : '键盘'}
                      >
                        <InputDeviceIcon device={dev} className="h-8 w-8" />
                      </button>
                    ))}
                 </div>
              </div>
           </div>
        </div>

        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">赛道状况</label>
          <div className="flex gap-4">
            <button
              type="button"
              onClick={() => setConditions('Dry')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Dry' 
                  ? 'bg-orange-500/20 border-orange-500 text-orange-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              ☀️ 干地
            </button>
            <button
              type="button"
              onClick={() => setConditions('Wet')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Wet' 
                  ? 'bg-blue-500/20 border-blue-500 text-blue-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              🌧️ 湿地
            </button>
          </div>
        </div>

        {error && (
          <div className="bg-yellow-900/50 border border-yellow-500/50 text-yellow-200 px-4 py-3 rounded text-sm font-semibold break-words">
            ⚠️ {error}
          </div>
        )}

        {successMessage && (
           <div className="bg-green-900/50 border border-green-500/50 text-green-200 px-4 py-3 rounded text-sm font-semibold flex items-center gap-2">
             ✅ {successMessage}
           </div>
        )}

        <div className="flex gap-3 pt-4">
          <Button type="button" variant="ghost" onClick={onCancel} className="flex-1" disabled={isSubmitting || isAnalyzing}>
            {isEditing ? '取消编辑' : '返回'}
          </Button>
          <Button type="submit" className="flex-1" disabled={!!successMessage || isSubmitting || isAnalyzing} isLoading={isSubmitting}>
            {isEditing ? '更新成绩' : '提交成绩'}
          </Button>
        </div>
      </form>
    </div>
  );
};

export default SubmitLapForm;

import React, { useState, useRef, useEffect } from 'react';
import { Track, User, LapTime, InputDevice } from '../types';
import { CARS, TRACKS } from '../constants';
import { submitLapTime, updateLapTime } from '../services/storageService';
import Button from './Button';
import Input from './Input';
import InputDeviceIcon from './InputDeviceIcon';
import Tesseract from 'tesseract.js';

interface SubmitLapFormProps {
  track: Track;
  user: User;
  onSuccess: () => void;
  onCancel: () => void;
  initialData?: LapTime | null;
}

interface CropBox {
  x: number;
  y: number;
  width: number;
  height: number;
}

type CropMode = 'TRACK' | 'DATA';

const SubmitLapForm: React.FC<SubmitLapFormProps> = ({ track: initialTrack, user, onSuccess, onCancel, initialData }) => {
  // --- Form State ---
  const [targetTrackId, setTargetTrackId] = useState(initialData?.trackId || initialTrack.id);
  const [carId, setCarId] = useState(initialData?.carId || CARS[0].id);
  const [minutes, setMinutes] = useState(initialData?.minutes.toString() || '');
  const [seconds, setSeconds] = useState(initialData?.seconds.toString() || '');
  const [millis, setMillis] = useState(initialData?.milliseconds.toString() || '');
  const [conditions, setConditions] = useState<'Dry' | 'Wet'>(initialData?.conditions || 'Dry');
  const [trackTemp, setTrackTemp] = useState(initialData?.trackTemp?.toString() || '');
  const [inputDevice, setInputDevice] = useState<InputDevice>(initialData?.inputDevice || 'Wheel');
  const [isVerified, setIsVerified] = useState<boolean>(initialData?.isVerified || false);

  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // --- OCR & Image State ---
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [ocrProgress, setOcrProgress] = useState<string>('');
  const [previewImage, setPreviewImage] = useState<string | null>(null);

  // --- Editor Modal State ---
  const [showEditor, setShowEditor] = useState(false);
  const [activeCropMode, setActiveCropMode] = useState<CropMode>('DATA'); // Default to data row as it's most important
  const [trackBox, setTrackBox] = useState<CropBox | null>(null);
  const [dataBox, setDataBox] = useState<CropBox | null>(null);

  // --- Dragging Logic ---
  const [isDragging, setIsDragging] = useState(false);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });

  const fileInputRef = useRef<HTMLInputElement>(null);
  const imgRef = useRef<HTMLImageElement>(null); // Ref for image inside modal
  const containerRef = useRef<HTMLDivElement>(null); // Ref for container inside modal

  const isEditing = !!initialData;

  // Cleanup on unmount
  useEffect(() => {
    return () => {
       if (previewImage) URL.revokeObjectURL(previewImage); // Good practice if we used blob URLs, though here we use base64 mostly
    }
  }, []);

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      setPreviewImage(base64String);
      setTrackBox(null);
      setDataBox(null);
      setShowEditor(true); // Open editor immediately upon upload
    };
    reader.readAsDataURL(file);
  };

  // --- MOUSE EVENTS FOR CROPPING (INSIDE MODAL) ---

  const getRelativeCoords = (e: React.MouseEvent) => {
    if (!containerRef.current) return { x: 0, y: 0 };
    const rect = containerRef.current.getBoundingClientRect();
    // Calculate scale in case image is resized by CSS
    // However, for crop box DISPLAY, we just need coordinates relative to the container DOM element
    return {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top
    };
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if (!previewImage || isAnalyzing) return;
    const coords = getRelativeCoords(e);
    setIsDragging(true);
    setStartPos(coords);

    // Initialize the box being drawn
    const newBox = { x: coords.x, y: coords.y, width: 0, height: 0 };
    if (activeCropMode === 'TRACK') setTrackBox(newBox);
    else setDataBox(newBox);
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging) return;
    const current = getRelativeCoords(e);

    const width = current.x - startPos.x;
    const height = current.y - startPos.y;

    // Allow dragging in any direction (calculate top-left)
    const normalizedBox = {
      x: width > 0 ? startPos.x : current.x,
      y: height > 0 ? startPos.y : current.y,
      width: Math.abs(width),
      height: Math.abs(height)
    };

    if (activeCropMode === 'TRACK') setTrackBox(normalizedBox);
    else setDataBox(normalizedBox);
  };

  const handleMouseUp = () => {
    setIsDragging(false);
    // Cleanup tiny accidental clicks
    const cleanup = (box: CropBox | null) => (box && (box.width < 10 || box.height < 10) ? null : box);
    if (activeCropMode === 'TRACK') setTrackBox(prev => cleanup(prev));
    else setDataBox(prev => cleanup(prev));
  };

  // --- CROP IMAGE HELPER ---
  const getCroppedDataUrl = (box: CropBox): string | null => {
    const image = imgRef.current;
    if (!image || !box) return null;

    const canvas = document.createElement('canvas');
    // Calculate scale factor (Natural Size / Displayed Size)
    // The box coordinates are based on the Displayed Size (clientWidth/clientHeight)
    const scaleX = image.naturalWidth / image.width;
    const scaleY = image.naturalHeight / image.height;

    canvas.width = box.width * scaleX;
    canvas.height = box.height * scaleY;

    const ctx = canvas.getContext('2d');
    if (!ctx) return null;

    ctx.drawImage(
      image,
      box.x * scaleX,     // Source X
      box.y * scaleY,     // Source Y
      box.width * scaleX, // Source Width
      box.height * scaleY,// Source Height
      0, 0,               // Dest X, Y
      canvas.width,       // Dest Width
      canvas.height       // Dest Height
    );

    return canvas.toDataURL('image/jpeg');
  };

  // --- Helper: Fuzzy Match Scorer ---
  const calculateMatchScore = (sourceText: string, targetName: string) => {
    const text = sourceText.toLowerCase();
    const tokens = targetName.toLowerCase().split(/[\s\-_()]+/).filter(t => t.length > 2);

    let score = 0;
    tokens.forEach(token => {
      if (text.includes(token)) {
        if (/\d/.test(token)) score += 2;
        else score += 1;
      }
    });
    return score;
  };

  // --- MAIN ANALYSIS FUNCTION ---
  const analyzeCrops = async () => {
    if (!previewImage) return;

    // If no Data box is selected, warn user, or fallback to full image?
    // Let's enforce Data box for better UX, or fallback to full image if absolutely nothing selected
    const hasDataBox = !!dataBox;
    const hasTrackBox = !!trackBox;

    if (!hasDataBox && !hasTrackBox) {
       setError("请至少框选一个区域进行识别。");
       return;
    }

    setIsAnalyzing(true);
    setOcrProgress('初始化 OCR 引擎...');
    setError('');
    setShowEditor(false); // Close modal to show progress on main form

    try {
      let detectedTrackId = targetTrackId;
      let detectedCarId = carId;
      let detectedTime = null;
      let detectedTemp = null;
      let infoLog: string[] = [];

      // 1. ANALYZE TRACK CROP (If exists)
      if (trackBox) {
         setOcrProgress('正在分析赛道名称...');
         const trackImg = getCroppedDataUrl(trackBox);
         if (trackImg) {
            const result = await Tesseract.recognize(trackImg, 'eng');
            const text = result.data.text;
            console.log("[OCR Track]:", text);

            let bestTrackScore = 0;
            let bestTId = null;

            TRACKS.forEach(t => {
               // Bonus for exact ID match (e.g. "monza")
               const idMatch = text.toLowerCase().includes(t.id) ? 3 : 0;
               const score = calculateMatchScore(text, t.name) + idMatch;
               if (score > bestTrackScore) {
                  bestTrackScore = score;
                  bestTId = t.id;
               }
            });

            if (bestTId && bestTrackScore > 0) {
               detectedTrackId = bestTId;
               const tName = TRACKS.find(t => t.id === bestTId)?.name;
               infoLog.push(`赛道: ${tName}`);
            }
         }
      }

      // 2. ANALYZE DATA CROP (If exists)
      if (dataBox) {
         setOcrProgress('正在分析数据行 (车型/圈速)...');
         const dataImg = getCroppedDataUrl(dataBox);
         if (dataImg) {
            const result = await Tesseract.recognize(dataImg, 'eng');
            const text = result.data.text;
            console.log("[OCR Data]:", text);

            // A. Car Detection
            let bestCarScore = 0;
            let bestCId = null;
            CARS.forEach(c => {
               const fullName = `${c.brand} ${c.name}`;
               const score = calculateMatchScore(text, fullName);
               if (score > bestCarScore) {
                  bestCarScore = score;
                  bestCId = c.id;
               }
            });
            if (bestCId && bestCarScore >= 1) { // Lower threshold for cropped data
               detectedCarId = bestCId;
               const cName = CARS.find(c => c.id === bestCId)?.name;
               infoLog.push(`车型: ${cName}`);
            }

            // B. Time Detection
            const timeRegex = /\b([0-9]{1,2})[:.;,]([0-5][0-9])[:.;,](\d{2,3})\b/g;
            const matches = [...text.matchAll(timeRegex)];

            if (matches.length > 0) {
               const candidates = matches.map(match => {
                  const m = parseInt(match[1]);
                  const s = parseInt(match[2]);
                  let msStr = match[3];
                  if (msStr.length === 2) msStr += "0"; 
                  const ms = parseInt(msStr);
                  const total = (m * 60 * 1000) + (s * 1000) + ms;
                  return { m, s, ms, total };
               }).filter(c => c.total > 30000 && c.total < 1200000); // Sanity check

               if (candidates.length > 0) {
                  candidates.sort((a, b) => a.total - b.total);
                  detectedTime = candidates[0]; // Best time
                  infoLog.push(`圈速: ${detectedTime.m}:${detectedTime.s}.${detectedTime.ms}`);
               }
            }

            // C. Temp Detection (Try data box first)
            const tempRegex = /(\d{1,2})\s?°?C/i;
            const tempMatch = text.match(tempRegex);
            if (tempMatch) {
               detectedTemp = tempMatch[1];
               infoLog.push(`温度: ${detectedTemp}°C`);
            }
         }
      }

      // APPLY RESULTS
      if (detectedTrackId !== targetTrackId) setTargetTrackId(detectedTrackId);
      if (detectedCarId !== carId) setCarId(detectedCarId);
      if (detectedTemp) setTrackTemp(detectedTemp);

      if (detectedTime) {
         setMinutes(detectedTime.m.toString());
         setSeconds(detectedTime.s.toString());
         setMillis(detectedTime.ms.toString());
         setIsVerified(true);
         setSuccessMessage(`识别成功: ${infoLog.join(' | ')}`);
      } else {
         if (infoLog.length > 0) {
             setSuccessMessage(`部分识别: ${infoLog.join(' | ')} (未找到有效圈速)`);
         } else {
             throw new Error("未能识别出有效信息，请尝试调整框选区域。");
         }
      }

    } catch (err: any) {
      console.error("OCR Analysis Failed:", err);
      setError("识别失败: " + (err.message || "未知错误"));
      setIsVerified(false);
    } finally {
      setIsAnalyzing(false);
      setOcrProgress('');
      setTimeout(() => setSuccessMessage(''), 6000);
    }
  };

  const handleManualTimeChange = (setter: React.Dispatch<React.SetStateAction<string>>, value: string) => {
    setter(value);
    setIsVerified(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMessage('');
    setIsSubmitting(true);

    const m = parseInt(minutes);
    const s = parseInt(seconds);
    const ms = parseInt(millis);
    const tTemp = trackTemp ? parseInt(trackTemp) : undefined;

    if (isNaN(m) || isNaN(s) || isNaN(ms)) {
      setError('请输入有效的圈速。');
      setIsSubmitting(false);
      return;
    }
    if (s >= 60) {
      setError('秒数必须小于60。');
      setIsSubmitting(false);
      return;
    }
    if (ms >= 1000) {
      setError('毫秒数必须小于1000。');
      setIsSubmitting(false);
      return;
    }

    const totalMilliseconds = (m * 60 * 1000) + (s * 1000) + ms;

    const generateId = () => {
      if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
      }
      return Date.now().toString(36) + Math.random().toString(36).substr(2);
    };

    const lapData: LapTime = {
      id: initialData?.id || generateId(),
      username: user.username,
      userEmail: user.email, 
      trackId: targetTrackId, 
      carId,
      minutes: m,
      seconds: s,
      milliseconds: ms,
      totalMilliseconds,
      timestamp: initialData?.timestamp || new Date().toISOString(),
      conditions,
      trackTemp: tTemp,
      inputDevice,
      isVerified: isVerified
    };

    let result;
    if (isEditing) {
       result = await updateLapTime(lapData);
    } else {
       result = await submitLapTime(lapData);
    }

    if (result.success) {
      setSuccessMessage(result.message);
      setTimeout(() => {
        onSuccess();
      }, 1500);
    } else {
      setError(result.message);
    }
    setIsSubmitting(false);
  };

  return (
    <>
    <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-2xl max-w-lg mx-auto w-full animate-fade-in-up">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold text-white flex items-center gap-2">
          <span className="text-red-500">{isEditing ? '编辑圈速' : '录入圈速'}</span>
        </h2>
        <div className="flex items-center gap-2">
          {isVerified && (
             <div className="flex items-center gap-1 text-xs bg-green-900/40 text-green-400 px-2 py-1 rounded border border-green-800">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M6.267 3.455a3.066 3.066 0 001.745-.723 3.066 3.066 0 013.976 0 3.066 3.066 0 001.745.723 3.066 3.066 0 012.812 2.812c.051.643.304 1.254.723 1.745a3.066 3.066 0 010 3.976 3.066 3.066 0 00-.723 1.745 3.066 3.066 0 01-2.812 2.812 3.066 3.066 0 00-1.745.723 3.066 3.066 0 01-3.976 0 3.066 3.066 0 00-1.745-.723 3.066 3.066 0 01-2.812-2.812 3.066 3.066 0 00-.723-1.745 3.066 3.066 0 010-3.976 3.066 3.066 0 00.723-1.745 3.066 3.066 0 012.812-2.812zm7.44 5.252a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
               </svg>
               OCR 已验证
             </div>
          )}
        </div>
      </div>

      {/* Image Upload Trigger */}
      <div className="mb-6">
        <input 
          type="file" 
          accept="image/*" 
          className="hidden" 
          ref={fileInputRef}
          onChange={handleImageUpload}
        />

        <button 
          type="button"
          onClick={() => previewImage ? setShowEditor(true) : fileInputRef.current?.click()}
          className="w-full flex flex-col items-center justify-center gap-2 py-6 bg-slate-900/50 rounded-lg border border-slate-700 border-dashed hover:border-red-500/50 transition-colors group relative overflow-hidden"
        >
          {previewImage ? (
            <>
               <img src={previewImage} className="absolute inset-0 w-full h-full object-cover opacity-30 group-hover:opacity-20 transition-opacity" />
               <div className="relative z-10 flex flex-col items-center">
                  <div className="bg-red-600 p-2 rounded-full mb-2 shadow-lg">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                    </svg>
                  </div>
                  <span className="font-bold text-white">点击打开编辑器</span>
                  <span className="text-xs text-slate-400">调整选区以提高准确率</span>
               </div>
            </>
          ) : (
            <>
              <div className="bg-slate-800 p-3 rounded-full group-hover:scale-110 transition-transform">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
                </svg>
              </div>
              <span className="text-sm font-bold text-slate-300">
                上传游戏截图 (OCR)
              </span>
              <span className="text-xs text-slate-500 text-center max-w-xs px-4">
                 支持双重框选：分别识别<br/>【赛道名称】和【车型圈速】
              </span>
            </>
          )}
        </button>

        {/* Status Indicator */}
        {isAnalyzing && (
            <div className="mt-2 flex items-center justify-center gap-2 text-xs text-slate-400 animate-pulse">
                <span className="w-2 h-2 bg-red-500 rounded-full"></span>
                {ocrProgress || '处理中...'}
            </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Track Selection */}
        <div>
           <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">赛道</label>
           </div>
           <select 
             value={targetTrackId} 
             onChange={(e) => setTargetTrackId(e.target.value)}
             className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:border-red-500 focus:outline-none focus:ring-1 focus:ring-red-500"
           >
             {TRACKS.map(t => (
               <option key={t.id} value={t.id}>{t.name}</option>
             ))}
           </select>
        </div>

        {/* Car Selection */}
        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">车辆</label>
          <select 
            value={carId} 
            onChange={(e) => setCarId(e.target.value)}
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:border-red-500 focus:outline-none focus:ring-1 focus:ring-red-500"
          >
            {CARS.map(car => (
              <option key={car.id} value={car.id}>
                [{car.class}] {car.brand} {car.name}
              </option>
            ))}
          </select>
        </div>

        {/* Lap Time Inputs */}
        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">圈速成绩</label>
          <div className="flex items-end gap-2">
            <div className="flex-1">
              <Input 
                placeholder="00" 
                value={minutes}
                onChange={(e) => handleManualTimeChange(setMinutes, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="59"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">分</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">:</span>
            <div className="flex-1">
              <Input 
                placeholder="00" 
                value={seconds}
                onChange={(e) => handleManualTimeChange(setSeconds, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="59"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">秒</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">.</span>
            <div className="flex-1">
              <Input 
                placeholder="000" 
                value={millis}
                onChange={(e) => handleManualTimeChange(setMillis, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="999"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">毫秒</span>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">赛道温度 (°C)</label>
              <div className="relative">
                <Input
                  type="number"
                  placeholder="24"
                  value={trackTemp}
                  onChange={(e) => setTrackTemp(e.target.value)}
                  className={isAnalyzing ? 'opacity-50' : ''}
                />
                <span className="absolute right-4 top-3.5 text-slate-500">°C</span>
              </div>
           </div>

           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">输入设备</label>
              <div className="flex flex-col gap-2">
                 <div className="grid grid-cols-3 gap-2">
                    {(['Wheel', 'Gamepad', 'Keyboard'] as InputDevice[]).map((dev) => (
                      <button
                        key={dev}
                        type="button"
                        onClick={() => setInputDevice(dev)}
                        className={`flex flex-col items-center justify-center p-3 rounded-lg border transition-all ${
                          inputDevice === dev
                            ? 'bg-red-600 border-red-500 text-white shadow-lg shadow-red-900/20'
                            : 'bg-slate-900 border-slate-700 text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                        }`}
                      >
                        <InputDeviceIcon device={dev} className="h-8 w-8" />
                      </button>
                    ))}
                 </div>
              </div>
           </div>
        </div>

        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">赛道状况</label>
          <div className="flex gap-4">
            <button
              type="button"
              onClick={() => setConditions('Dry')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Dry' 
                  ? 'bg-orange-500/20 border-orange-500 text-orange-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              ☀️ 干地
            </button>
            <button
              type="button"
              onClick={() => setConditions('Wet')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Wet' 
                  ? 'bg-blue-500/20 border-blue-500 text-blue-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              🌧️ 湿地
            </button>
          </div>
        </div>

        {error && (
          <div className="bg-yellow-900/50 border border-yellow-500/50 text-yellow-200 px-4 py-3 rounded text-sm font-semibold break-words">
            ⚠️ {error}
          </div>
        )}

        {successMessage && (
           <div className="bg-green-900/50 border border-green-500/50 text-green-200 px-4 py-3 rounded text-sm font-semibold flex items-center gap-2">
             ✅ {successMessage}
           </div>
        )}

        <div className="flex gap-3 pt-4">
          <Button type="button" variant="ghost" onClick={onCancel} className="flex-1" disabled={isSubmitting || isAnalyzing}>
            {isEditing ? '取消编辑' : '返回'}
          </Button>
          <Button type="submit" className="flex-1" disabled={!!successMessage || isSubmitting || isAnalyzing} isLoading={isSubmitting}>
            {isEditing ? '更新成绩' : '提交成绩'}
          </Button>
        </div>
      </form>
    </div>

    {/* --- FULL SCREEN EDITOR MODAL --- */}
    {showEditor && previewImage && (
      <div className="fixed inset-0 z-[100] bg-slate-950 flex flex-col animate-fade-in">
         {/* Editor Header */}
         <div className="flex items-center justify-between px-6 py-4 border-b border-slate-800 bg-slate-900">
            <div>
               <h3 className="text-white font-bold text-lg">图片OCR编辑器</h3>
               <p className="text-slate-400 text-sm hidden sm:block">
                  请分别框选识别区域，框选完成后点击“开始识别”。
               </p>
            </div>
            <div className="flex gap-3">
               <Button variant="secondary" onClick={() => setShowEditor(false)}>取消</Button>
               <Button variant="primary" onClick={analyzeCrops} disabled={!dataBox && !trackBox}>
                  开始识别
               </Button>
            </div>
         </div>

         {/* Editor Toolbar */}
         <div className="flex justify-center gap-4 py-3 bg-slate-900 border-b border-slate-800">
             <button
                onClick={() => setActiveCropMode('TRACK')}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg border transition-all ${
                   activeCropMode === 'TRACK' 
                   ? 'bg-blue-900/50 border-blue-500 text-blue-200' 
                   : 'bg-slate-800 border-slate-700 text-slate-400 hover:text-white'
                }`}
             >
                <span className="w-3 h-3 bg-blue-500 rounded-sm"></span>
                1. 框选赛道名称 (可选)
             </button>
             <button
                onClick={() => setActiveCropMode('DATA')}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg border transition-all ${
                   activeCropMode === 'DATA' 
                   ? 'bg-red-900/50 border-red-500 text-red-200' 
                   : 'bg-slate-800 border-slate-700 text-slate-400 hover:text-white'
                }`}
             >
                <span className="w-3 h-3 bg-red-500 rounded-sm"></span>
                2. 框选【车型+圈速】行 (必须)
             </button>
         </div>

         {/* Main Editor Area */}
         <div className="flex-1 overflow-auto bg-slate-950 p-4 flex items-center justify-center select-none">
            <div 
               ref={containerRef}
               className="relative cursor-crosshair shadow-2xl border border-slate-800 inline-block"
               onMouseDown={handleMouseDown}
               onMouseMove={handleMouseMove}
               onMouseUp={handleMouseUp}
               onMouseLeave={handleMouseUp}
            >
               <img 
                  ref={imgRef}
                  src={previewImage} 
                  alt="Editor View"
                  className="max-h-[70vh] max-w-full object-contain block pointer-events-none"
                  draggable={false}
               />

               {/* Track Box Overlay */}
               {trackBox && (
                  <div 
                     className="absolute border-2 border-blue-500 bg-blue-500/20 pointer-events-none"
                     style={{
                        left: trackBox.x,
                        top: trackBox.y,
                        width: trackBox.width,
                        height: trackBox.height,
                     }}
                  >
                     <div className="absolute -top-6 left-0 bg-blue-600 text-white text-[10px] px-1 rounded whitespace-nowrap shadow-sm">
                        赛道区域
                     </div>
                     <button
                        onMouseDown={(e) => { e.stopPropagation(); setTrackBox(null); }}
                        className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full w-5 h-5 flex items-center justify-center text-xs pointer-events-auto hover:bg-red-600"
                     >
                        ×
                     </button>
                  </div>
               )}

               {/* Data Box Overlay */}
               {dataBox && (
                  <div 
                     className="absolute border-2 border-red-500 bg-red-500/20 pointer-events-none"
                     style={{
                        left: dataBox.x,
                        top: dataBox.y,
                        width: dataBox.width,
                        height: dataBox.height,
                     }}
                  >
                     <div className="absolute -top-6 left-0 bg-red-600 text-white text-[10px] px-1 rounded whitespace-nowrap shadow-sm">
                        数据行 (车型/时间)
                     </div>
                     <button
                        onMouseDown={(e) => { e.stopPropagation(); setDataBox(null); }}
                        className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full w-5 h-5 flex items-center justify-center text-xs pointer-events-auto hover:bg-red-600"
                     >
                        ×
                     </button>
                  </div>
               )}
            </div>
         </div>

         {/* Footer Hint */}
         <div className="bg-slate-900 py-2 px-4 text-center text-xs text-slate-500 border-t border-slate-800">
            提示：可拖拽创建选区。如果图片过大，请使用鼠标滚轮上下滚动查看。
         </div>
      </div>
    )}
    </>
  );
};

export default SubmitLapForm;

import React, { useState, useRef } from 'react';
import { Track, User, LapTime, InputDevice } from '../types';
import { CARS, TRACKS } from '../constants';
import { submitLapTime, updateLapTime } from '../services/storageService';
import Button from './Button';
import Input from './Input';
import InputDeviceIcon from './InputDeviceIcon';
import { GoogleGenAI, Type } from "@google/genai";

interface SubmitLapFormProps {
  track: Track;
  user: User;
  onSuccess: () => void;
  onCancel: () => void;
  initialData?: LapTime | null;
}

const SubmitLapForm: React.FC<SubmitLapFormProps> = ({ track: initialTrack, user, onSuccess, onCancel, initialData }) => {
  // --- Form State ---
  const [targetTrackId, setTargetTrackId] = useState(initialData?.trackId || initialTrack.id);
  const [carId, setCarId] = useState(initialData?.carId || CARS[0].id);
  const [minutes, setMinutes] = useState(initialData?.minutes.toString() || '');
  const [seconds, setSeconds] = useState(initialData?.seconds.toString() || '');
  const [millis, setMillis] = useState(initialData?.milliseconds.toString() || '');
  const [conditions, setConditions] = useState<'Dry' | 'Wet'>(initialData?.conditions || 'Dry');
  const [trackTemp, setTrackTemp] = useState(initialData?.trackTemp?.toString() || '');
  const [inputDevice, setInputDevice] = useState<InputDevice>(initialData?.inputDevice || 'Wheel');
  const [isVerified, setIsVerified] = useState<boolean>(initialData?.isVerified || false);

  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // --- AI Analysis State ---
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const isEditing = !!initialData;

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Preview
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      setPreviewImage(base64String);
      analyzeScreenshot(base64String); // Auto-start analysis
    };
    reader.readAsDataURL(file);
  };

  const analyzeScreenshot = async (base64Data: string) => {
    setIsAnalyzing(true);
    setError('');
    setSuccessMessage('');

    try {
      // 1. Prepare Base64 Data (Strip prefix)
      const match = base64Data.match(/^data:(.+);base64,(.+)$/);
      if (!match) throw new Error("Invalid image data");
      const mimeType = match[1];
      const rawBase64 = match[2];

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // 2. Prepare Context Lists for the AI to match against
      const trackList = TRACKS.map(t => `ID: "${t.id}", Name: "${t.name}"`).join('\n');
      const carList = CARS.map(c => `ID: "${c.id}", Car: "${c.brand} ${c.name}"`).join('\n');

      const prompt = `
        Analyze this screenshot from the racing simulator Assetto Corsa Competizione.

        Task: Identify the following details from the UI:
        1. Lap Time: Look for the highlighted lap time or the most prominent valid lap time row. (Format: Minutes:Seconds.Milliseconds).
        2. Track: Identify the race track. Match strictly to one of the IDs in the provided list.
        3. Car: Identify the car model used by the player. Match strictly to one of the IDs in the provided list.
        4. Track Temperature: Look for 'Track Temp' or ambient info (in Celsius).

        Data Lists for matching:
        --- TRACKS ---
        ${trackList}

        --- CARS ---
        ${carList}

        Constraint: If you cannot find a specific value, leave it null. Do not hallucinate.
      `;

      // 3. Call Gemini API with JSON Schema
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { mimeType, data: rawBase64 } },
            { text: prompt }
          ]
        },
        config: {
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              minutes: { type: Type.INTEGER },
              seconds: { type: Type.INTEGER },
              milliseconds: { type: Type.INTEGER },
              trackId: { type: Type.STRING },
              carId: { type: Type.STRING },
              trackTemp: { type: Type.INTEGER },
            },
            required: ["minutes", "seconds", "milliseconds"],
          }
        }
      });

      // 4. Handle Response
      const text = response.text;
      if (!text) throw new Error("AI returned empty response");

      const data = JSON.parse(text);
      console.log("AI Analysis Result:", data);

      let identifiedInfo = [];

      // Update Form State
      if (data.minutes !== undefined && data.minutes !== null) setMinutes(data.minutes.toString());
      if (data.seconds !== undefined && data.seconds !== null) setSeconds(data.seconds.toString());
      if (data.milliseconds !== undefined && data.milliseconds !== null) setMillis(data.milliseconds.toString());

      if (data.trackId && TRACKS.find(t => t.id === data.trackId)) {
        setTargetTrackId(data.trackId);
        identifiedInfo.push("赛道");
      }

      if (data.carId && CARS.find(c => c.id === data.carId)) {
        setCarId(data.carId);
        identifiedInfo.push("车型");
      }

      if (data.trackTemp) {
        setTrackTemp(data.trackTemp.toString());
        identifiedInfo.push("温度");
      }

      setIsVerified(true);
      setSuccessMessage(`智能识别完成! (${identifiedInfo.join(', ')})`);

    } catch (err: any) {
      console.error("AI Error:", err);
      setError("识别失败: " + (err.message || "无法分析图片，请手动输入。"));
      setIsVerified(false);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleManualTimeChange = (setter: React.Dispatch<React.SetStateAction<string>>, value: string) => {
    setter(value);
    setIsVerified(false); // Manually editing invalidates the AI verification
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMessage('');
    setIsSubmitting(true);

    const m = parseInt(minutes);
    const s = parseInt(seconds);
    const ms = parseInt(millis);
    const tTemp = trackTemp ? parseInt(trackTemp) : undefined;

    if (isNaN(m) || isNaN(s) || isNaN(ms)) {
      setError('请输入有效的圈速。');
      setIsSubmitting(false);
      return;
    }
    if (s >= 60) {
      setError('秒数必须小于60。');
      setIsSubmitting(false);
      return;
    }
    if (ms >= 1000) {
      setError('毫秒数必须小于1000。');
      setIsSubmitting(false);
      return;
    }

    const totalMilliseconds = (m * 60 * 1000) + (s * 1000) + ms;

    const generateId = () => {
      if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
      }
      return Date.now().toString(36) + Math.random().toString(36).substr(2);
    };

    const lapData: LapTime = {
      id: initialData?.id || generateId(),
      username: user.username,
      userEmail: user.email, 
      trackId: targetTrackId, 
      carId,
      minutes: m,
      seconds: s,
      milliseconds: ms,
      totalMilliseconds,
      timestamp: initialData?.timestamp || new Date().toISOString(),
      conditions,
      trackTemp: tTemp,
      inputDevice,
      isVerified: isVerified
    };

    let result;
    if (isEditing) {
       result = await updateLapTime(lapData);
    } else {
       result = await submitLapTime(lapData);
    }

    if (result.success) {
      setSuccessMessage(result.message);
      setTimeout(() => {
        onSuccess();
      }, 1500);
    } else {
      setError(result.message);
    }
    setIsSubmitting(false);
  };

  return (
    <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-2xl max-w-lg mx-auto w-full animate-fade-in-up">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold text-white flex items-center gap-2">
          <span className="text-red-500">{isEditing ? '编辑圈速' : '录入圈速'}</span>
        </h2>
        <div className="flex items-center gap-2">
          {isVerified && (
             <div className="flex items-center gap-1 text-xs bg-green-900/40 text-green-400 px-2 py-1 rounded border border-green-800">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M6.267 3.455a3.066 3.066 0 001.745-.723 3.066 3.066 0 013.976 0 3.066 3.066 0 001.745.723 3.066 3.066 0 012.812 2.812c.051.643.304 1.254.723 1.745a3.066 3.066 0 010 3.976 3.066 3.066 0 00-.723 1.745 3.066 3.066 0 01-2.812 2.812 3.066 3.066 0 00-1.745.723 3.066 3.066 0 01-3.976 0 3.066 3.066 0 00-1.745-.723 3.066 3.066 0 01-2.812-2.812 3.066 3.066 0 00-.723-1.745 3.066 3.066 0 010-3.976 3.066 3.066 0 00.723-1.745 3.066 3.066 0 012.812-2.812zm7.44 5.252a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
               </svg>
               AI 已验证
             </div>
          )}
          <div className="text-xs bg-slate-900 px-3 py-1 rounded-full border border-slate-700 text-slate-400">
             Gemini Vision AI
          </div>
        </div>
      </div>

      {/* Image Upload Trigger */}
      <div className="mb-6">
        <input 
          type="file" 
          accept="image/*" 
          className="hidden" 
          ref={fileInputRef}
          onChange={handleImageUpload}
        />

        {!previewImage ? (
          <button 
            type="button"
            onClick={() => fileInputRef.current?.click()}
            className="w-full flex flex-col items-center justify-center gap-2 py-8 bg-slate-900/50 rounded-lg border border-slate-700 border-dashed hover:border-red-500/50 transition-colors group relative overflow-hidden"
          >
              <div className="bg-slate-800 p-3 rounded-full group-hover:scale-110 transition-transform">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
                </svg>
              </div>
              <span className="text-sm font-bold text-slate-300">
                上传游戏截图
              </span>
              <span className="text-xs text-slate-500 text-center max-w-xs px-4">
                 AI 自动识别车型、赛道和圈速
              </span>
          </button>
        ) : (
          <div className="relative rounded-lg overflow-hidden border border-slate-600 bg-slate-950">
             <img src={previewImage} alt="Preview" className="w-full max-h-64 object-contain opacity-80" />

             {isAnalyzing && (
               <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/60 backdrop-blur-sm">
                  <span className="w-8 h-8 border-4 border-red-500 border-t-transparent rounded-full animate-spin mb-3"></span>
                  <span className="text-white font-bold text-sm shadow-black drop-shadow-md animate-pulse">正在分析图片...</span>
               </div>
             )}

             {!isAnalyzing && (
               <button 
                type="button"
                onClick={() => {
                  setPreviewImage(null);
                  setIsVerified(false);
                  if (!isEditing) {
                     setMinutes(''); setSeconds(''); setMillis('');
                  }
                }}
                className="absolute top-2 right-2 bg-black/60 text-white rounded-full p-1.5 hover:bg-red-600 transition-colors"
                title="清除图片"
               >
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                   <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                 </svg>
               </button>
             )}
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Track Selection */}
        <div>
           <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">赛道</label>
           </div>
           <select 
             value={targetTrackId} 
             onChange={(e) => setTargetTrackId(e.target.value)}
             className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:border-red-500 focus:outline-none focus:ring-1 focus:ring-red-500"
           >
             {TRACKS.map(t => (
               <option key={t.id} value={t.id}>{t.name}</option>
             ))}
           </select>
        </div>

        {/* Car Selection */}
        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">车辆</label>
          <select 
            value={carId} 
            onChange={(e) => setCarId(e.target.value)}
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:border-red-500 focus:outline-none focus:ring-1 focus:ring-red-500"
          >
            {CARS.map(car => (
              <option key={car.id} value={car.id}>
                [{car.class}] {car.brand} {car.name}
              </option>
            ))}
          </select>
        </div>

        {/* Lap Time Inputs */}
        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">圈速成绩</label>
          <div className="flex items-end gap-2">
            <div className="flex-1">
              <Input 
                placeholder="00" 
