    // 1. Preview
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      setPreviewImage(base64String);
      analyzeScreenshot(base64String); // Auto-start analysis
    };
    reader.readAsDataURL(file);
  };

  const analyzeScreenshot = async (base64Full: string) => {
    setIsAnalyzing(true);
    setError('');

    try {
      // Clean base64 string (remove data:image/png;base64, prefix)
      const base64Data = base64Full.split(',')[1];
      const mimeType = base64Full.split(';')[0].split(':')[1];

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Prepare Contexts
      const carListContext = CARS.map(c => `ID: "${c.id}", Name: "${c.brand} ${c.name}"`).join('\n');
      const trackListContext = TRACKS.map(t => `ID: "${t.id}", Name: "${t.name}"`).join('\n');

      const prompt = `
        Analyze this Assetto Corsa Competizione screenshot.

        Tasks:
        1. Identify the Lap Time (MM:SS.ms).
        2. Identify the Car Model and match to the provided Car List.
        3. Identify the Track Name from the UI/Environment and match to the provided Track List.
        4. Identify Track Temperature (e.g., "Track: 24°C").

        Lists:
        [CARS]
        ${carListContext}

        [TRACKS]
        ${trackListContext}
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { mimeType: mimeType, data: base64Data } },
            { text: prompt }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              minutes: { type: Type.INTEGER },
              seconds: { type: Type.INTEGER },
              milliseconds: { type: Type.INTEGER },
              carId: { type: Type.STRING, description: "ID from Car List" },
              trackId: { type: Type.STRING, description: "ID from Track List" },
              trackTemp: { type: Type.INTEGER },
            },
            required: ["minutes", "seconds", "milliseconds"]
          }
        }
      });

      const resultText = response.text;
      if (resultText) {
        let cleanText = resultText.trim();
        // Robust cleaning of markdown code blocks
        if (cleanText.startsWith('```')) {
            cleanText = cleanText.replace(/^```json\s?/, '').replace(/^```\s?/, '').replace(/```$/, '');
        }

        const data = JSON.parse(cleanText);

        if (data.minutes !== undefined) setMinutes(data.minutes.toString());
        if (data.seconds !== undefined) setSeconds(data.seconds.toString());
        if (data.milliseconds !== undefined) setMillis(data.milliseconds.toString());
        if (data.trackTemp !== undefined) setTrackTemp(data.trackTemp.toString());

        if (data.carId && CARS.some(c => c.id === data.carId)) {
          setCarId(data.carId);
        }

        if (data.trackId && TRACKS.some(t => t.id === data.trackId)) {
          setTargetTrackId(data.trackId);
        }

        // Successfully analyzed via AI -> Set as Verified
        setIsVerified(true);
      }

    } catch (err: any) {
      console.error("AI Analysis Failed:", err);

      let friendlyError = "AI 识别失败，请确保截图清晰包含数据。";
      const errorStr = err.message || JSON.stringify(err);

      if (errorStr.includes("429") || errorStr.includes("RESOURCE_EXHAUSTED") || errorStr.includes("quota")) {
        friendlyError = "AI 服务配额已耗尽 (429)。请等待几秒后点击重试。";
      } else if (errorStr.includes("503") || errorStr.includes("overloaded")) {
        friendlyError = "AI 服务繁忙，请稍后再试。";
      }

      setError(friendlyError);
      setIsVerified(false); // Analysis failed, so not verified
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleManualTimeChange = (setter: React.Dispatch<React.SetStateAction<string>>, value: string) => {
    setter(value);
    // If user manually changes the time, invalidate the AI verification
    setIsVerified(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMessage('');
    setIsSubmitting(true);

    const m = parseInt(minutes);
    const s = parseInt(seconds);
    const ms = parseInt(millis);
    const tTemp = trackTemp ? parseInt(trackTemp) : undefined;

    if (isNaN(m) || isNaN(s) || isNaN(ms)) {
      setError('请输入有效的圈速。');
      setIsSubmitting(false);
      return;
    }
    if (s >= 60) {
      setError('秒数必须小于60。');
      setIsSubmitting(false);
      return;
    }
    if (ms >= 1000) {
      setError('毫秒数必须小于1000。');
      setIsSubmitting(false);
      return;
    }

    const totalMilliseconds = (m * 60 * 1000) + (s * 1000) + ms;

    const generateId = () => {
      if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
      }
      return Date.now().toString(36) + Math.random().toString(36).substr(2);
    };

    const lapData: LapTime = {
      id: initialData?.id || generateId(), // Preserve ID if editing
      username: user.username,
      userEmail: user.email, 
      trackId: targetTrackId, 
      carId,
      minutes: m,
      seconds: s,
      milliseconds: ms,
      totalMilliseconds,
      timestamp: initialData?.timestamp || new Date().toISOString(), // Preserve timestamp if editing, or use current
      conditions,
      trackTemp: tTemp,
      inputDevice,
      isVerified: isVerified
    };

    let result;
    if (isEditing) {
       // If editing, force update regardless of PB check (assumes correction)
       result = await updateLapTime(lapData);
    } else {
       // If new, use standard submission (checks PB)
       result = await submitLapTime(lapData);
    }

    if (result.success) {
      setSuccessMessage(result.message);
      setTimeout(() => {
        onSuccess();
      }, 1500);
    } else {
      setError(result.message);
    }
    setIsSubmitting(false);
  };

  const currentTrack = TRACKS.find(t => t.id === targetTrackId) || initialTrack;

  return (
    <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-2xl max-w-lg mx-auto w-full animate-fade-in-up">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold text-white flex items-center gap-2">
          <span className="text-red-500">{isEditing ? '编辑圈速' : '录入圈速'}</span>
        </h2>
        <div className="flex items-center gap-2">
          {isVerified && (
             <div className="flex items-center gap-1 text-xs bg-green-900/40 text-green-400 px-2 py-1 rounded border border-green-800">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M6.267 3.455a3.066 3.066 0 001.745-.723 3.066 3.066 0 013.976 0 3.066 3.066 0 001.745.723 3.066 3.066 0 012.812 2.812c.051.643.304 1.254.723 1.745a3.066 3.066 0 010 3.976 3.066 3.066 0 00-.723 1.745 3.066 3.066 0 01-2.812 2.812 3.066 3.066 0 00-1.745.723 3.066 3.066 0 01-3.976 0 3.066 3.066 0 00-1.745-.723 3.066 3.066 0 01-2.812-2.812 3.066 3.066 0 00-.723-1.745 3.066 3.066 0 010-3.976 3.066 3.066 0 00.723-1.745 3.066 3.066 0 012.812-2.812zm7.44 5.252a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
               </svg>
               已验证
             </div>
          )}
          <div className="text-xs bg-slate-900 px-3 py-1 rounded-full border border-slate-700 text-slate-400">
             {isEditing ? '编辑模式' : 'AI 辅助模式'}
          </div>
        </div>
      </div>

      {/* AI Upload Section - Available for both New and Edit */}
      <div className="mb-6 p-4 bg-slate-900/50 rounded-lg border border-slate-700 border-dashed hover:border-red-500/50 transition-colors">
        <input 
          type="file" 
          accept="image/*" 
          className="hidden" 
          ref={fileInputRef}
          onChange={handleImageUpload}
        />

        {!previewImage ? (
          <button 
            type="button"
            onClick={() => fileInputRef.current?.click()}
            className="w-full flex flex-col items-center justify-center gap-2 py-4 text-slate-400 hover:text-white transition-colors"
          >
            <div className="bg-slate-800 p-3 rounded-full animate-bounce">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
            </div>
            <span className="text-sm font-bold">
              {isEditing ? '上传新截图以更新数据' : '点击上传游戏截图'}
            </span>
            <span className="text-xs text-slate-500">
               {isEditing ? '这将覆盖当前数据并标记为已验证' : '必须上传截图以自动填充数据'}
            </span>
          </button>
        ) : (
          <div className="relative">
            <img 
              src={previewImage} 
              alt="Preview" 
              className="w-full h-32 object-cover rounded-lg opacity-80" 
            />
            {isAnalyzing && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/60 backdrop-blur-sm rounded-lg z-10">
                 <span className="w-8 h-8 border-4 border-red-500 border-t-transparent rounded-full animate-spin mb-2"></span>
                 <span className="text-white font-bold text-sm shadow-black drop-shadow-md">正在识别赛道与圈速...</span>
              </div>
            )}

            {!isAnalyzing && error && (
               <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/80 backdrop-blur-sm rounded-lg z-10 p-4 text-center">
                  <div className="text-red-400 text-sm font-bold mb-3">{error}</div>
                  <div className="flex gap-2">
                    <Button 
                      type="button" 
                      variant="primary" 
                      className="!py-1 !px-3 !text-xs"
                      onClick={(e) => {
                         e.stopPropagation();
                         analyzeScreenshot(previewImage);
                      }}
                    >
                      重试
                    </Button>
                    <Button 
                      type="button" 
                      variant="secondary" 
                      className="!py-1 !px-3 !text-xs"
                      onClick={() => {
                        setPreviewImage(null);
                        setError('');
                      }}
                    >
                      取消
                    </Button>
                  </div>
               </div>
            )}

            {!isAnalyzing && !error && (
              <button 
                type="button"
                onClick={() => {
                  setPreviewImage(null);
                  if (!isEditing) {
                      setMinutes('');
                      setSeconds('');
                      setMillis('');
                      setTrackTemp('');
                      setTargetTrackId(initialTrack.id);
                  }
                  setIsVerified(false); // Reset verified if image removed
                }}
                className="absolute top-2 right-2 bg-black/50 text-white rounded-full p-1 hover:bg-red-600 transition-colors z-20"
                title="清除并重新上传"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                </svg>
              </button>
            )}
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Track Display */}
        <div>
           <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">赛道</label>
           </div>
           <div className={`flex items-center gap-3 p-3 bg-slate-950 border border-slate-800 rounded-lg ${isAnalyzing ? 'opacity-50' : ''}`}>
              {currentTrack.imageUrl && (
                 <img src={currentTrack.imageUrl} className="h-8 w-8 object-contain brightness-0 invert opacity-50" alt="Track Icon"/>
              )}
              <div className="flex-1">
                 <div className="text-white font-bold">{currentTrack.name}</div>
                 <div className="text-xs text-slate-500">{currentTrack.country} • {currentTrack.length}</div>
              </div>
           </div>
        </div>

        {/* Car Selection */}
        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">车辆</label>
          <select 
            value={carId} 
            onChange={(e) => setCarId(e.target.value)}
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:border-red-500 focus:outline-none focus:ring-1 focus:ring-red-500"
          >
            {CARS.map(car => (
              <option key={car.id} value={car.id}>
                [{car.class}] {car.brand} {car.name}
              </option>
            ))}
          </select>
        </div>

        {/* Lap Time Inputs */}
        <div>
          <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">圈速成绩</label>
             {isVerified && (
               <span className="text-[10px] text-green-500 bg-green-900/20 px-1.5 rounded border border-green-800/50">已锁定验证</span>
             )}
          </div>
          <div className="flex items-end gap-2">
            <div className="flex-1">
              <Input 
                placeholder="00" 
                value={minutes}
                onChange={(e) => handleManualTimeChange(setMinutes, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="59"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">分</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">:</span>
            <div className="flex-1">
              <Input 
                placeholder="00" 
                value={seconds}
                onChange={(e) => handleManualTimeChange(setSeconds, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="59"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">秒</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">.</span>
            <div className="flex-1">
              <Input 
                placeholder="000" 
                value={millis}
                onChange={(e) => handleManualTimeChange(setMillis, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="999"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">毫秒</span>
            </div>
          </div>
          <div className="text-xs text-slate-500 mt-2 text-right">
             * 手动修改时间将取消验证状态
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">赛道温度 (°C)</label>
              <div className="relative">
                <Input
                  type="number"
                  placeholder="24"
                  value={trackTemp}
                  onChange={(e) => setTrackTemp(e.target.value)}
                  className={isAnalyzing ? 'opacity-50' : ''}
                />
                <span className="absolute right-4 top-3.5 text-slate-500">°C</span>
              </div>
           </div>

           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">输入设备</label>
              <div className="flex flex-col gap-2">
                 <div className="grid grid-cols-3 gap-2">
                    {(['Wheel', 'Gamepad', 'Keyboard'] as InputDevice[]).map((dev) => (
                      <button
                        key={dev}
                        type="button"
                        onClick={() => setInputDevice(dev)}
                        className={`flex flex-col items-center justify-center p-3 rounded-lg border transition-all ${
                          inputDevice === dev
                            ? 'bg-red-600 border-red-500 text-white shadow-lg shadow-red-900/20'
                            : 'bg-slate-900 border-slate-700 text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                        }`}
                        title={dev === 'Wheel' ? '方向盘' : dev === 'Gamepad' ? '手柄' : '键盘'}
                      >
                        <InputDeviceIcon device={dev} className="h-8 w-8" />
                      </button>
                    ))}
                 </div>
              </div>
           </div>
        </div>

        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">赛道状况</label>
          <div className="flex gap-4">
            <button
              type="button"
              onClick={() => setConditions('Dry')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Dry' 
                  ? 'bg-orange-500/20 border-orange-500 text-orange-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              ☀️ 干地
            </button>
            <button
              type="button"
              onClick={() => setConditions('Wet')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Wet' 
                  ? 'bg-blue-500/20 border-blue-500 text-blue-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              🌧️ 湿地
            </button>
          </div>
        </div>

        {error && !previewImage && (
          <div className="bg-yellow-900/50 border border-yellow-500/50 text-yellow-200 px-4 py-3 rounded text-sm font-semibold break-words">
            ⚠️ {error}
          </div>
        )}

        {successMessage && (
           <div className="bg-green-900/50 border border-green-500/50 text-green-200 px-4 py-3 rounded text-sm font-semibold flex items-center gap-2">
             ✅ {successMessage}
           </div>
        )}

        <div className="flex gap-3 pt-4">
          <Button type="button" variant="ghost" onClick={onCancel} className="flex-1" disabled={isSubmitting || isAnalyzing}>
            {isEditing ? '取消编辑' : '返回'}
          </Button>
          <Button type="submit" className="flex-1" disabled={!!successMessage || isSubmitting || isAnalyzing} isLoading={isSubmitting}>
            {isEditing ? '更新成绩' : '提交成绩'}
          </Button>
        </div>
      </form>
    </div>
  );
};

export default SubmitLapForm;

import React, { useState, useRef } from 'react';
import { Track, User, LapTime, InputDevice } from '../types';
import { CARS, TRACKS } from '../constants';
import { submitLapTime, updateLapTime } from '../services/storageService';
import Button from './Button';
import Input from './Input';
import InputDeviceIcon from './InputDeviceIcon';
import { GoogleGenAI, Type } from "@google/genai";

interface SubmitLapFormProps {
  track: Track;
  user: User;
  onSuccess: () => void;
  onCancel: () => void;
  initialData?: LapTime | null;
}

const SubmitLapForm: React.FC<SubmitLapFormProps> = ({ track: initialTrack, user, onSuccess, onCancel, initialData }) => {
  // State initialization
  const [targetTrackId, setTargetTrackId] = useState(initialData?.trackId || initialTrack.id);
  const [carId, setCarId] = useState(initialData?.carId || CARS[0].id);
  const [minutes, setMinutes] = useState(initialData?.minutes.toString() || '');
  const [seconds, setSeconds] = useState(initialData?.seconds.toString() || '');
  const [millis, setMillis] = useState(initialData?.milliseconds.toString() || '');
  const [conditions, setConditions] = useState<'Dry' | 'Wet'>(initialData?.conditions || 'Dry');
  const [trackTemp, setTrackTemp] = useState(initialData?.trackTemp?.toString() || '');
  const [inputDevice, setInputDevice] = useState<InputDevice>(initialData?.inputDevice || 'Wheel');
  const [isVerified, setIsVerified] = useState<boolean>(initialData?.isVerified || false);

  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // AI Analysis State
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const isEditing = !!initialData;

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // 1. Preview
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      setPreviewImage(base64String);
      analyzeScreenshot(base64String); // Auto-start analysis
    };
    reader.readAsDataURL(file);
  };

  const analyzeScreenshot = async (base64Full: string) => {
    setIsAnalyzing(true);
    setError('');

    try {
      // Clean base64 string (remove data:image/png;base64, prefix)
      const base64Data = base64Full.split(',')[1];
      const mimeType = base64Full.split(';')[0].split(':')[1];

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Prepare Contexts
      const carListContext = CARS.map(c => `ID: "${c.id}", Name: "${c.brand} ${c.name}"`).join('\n');
      const trackListContext = TRACKS.map(t => `ID: "${t.id}", Name: "${t.name}"`).join('\n');

      const prompt = `
        Analyze this Assetto Corsa Competizione screenshot.

        Tasks:
        1. Identify the Lap Time (MM:SS.ms).
        2. Identify the Car Model and match to the provided Car List.
        3. Identify the Track Name from the UI/Environment and match to the provided Track List.
        4. Identify Track Temperature (e.g., "Track: 24°C").

        Lists:
        [CARS]
        ${carListContext}

        [TRACKS]
        ${trackListContext}
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-2.0-flash',
        contents: {
          parts: [
            { inlineData: { mimeType: mimeType, data: base64Data } },
            { text: prompt }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              minutes: { type: Type.INTEGER },
              seconds: { type: Type.INTEGER },
              milliseconds: { type: Type.INTEGER },
              carId: { type: Type.STRING, description: "ID from Car List" },
              trackId: { type: Type.STRING, description: "ID from Track List" },
              trackTemp: { type: Type.INTEGER },
            },
            required: ["minutes", "seconds", "milliseconds"]
          }
        }
      });

      const resultText = response.text;
      if (resultText) {
        let cleanText = resultText.trim();
        // Robust cleaning of markdown code blocks
        if (cleanText.startsWith('```')) {
            cleanText = cleanText.replace(/^```json\s?/, '').replace(/^```\s?/, '').replace(/```$/, '');
        }

        const data = JSON.parse(cleanText);

        if (data.minutes !== undefined) setMinutes(data.minutes.toString());
        if (data.seconds !== undefined) setSeconds(data.seconds.toString());
        if (data.milliseconds !== undefined) setMillis(data.milliseconds.toString());
        if (data.trackTemp !== undefined) setTrackTemp(data.trackTemp.toString());

        if (data.carId && CARS.some(c => c.id === data.carId)) {
          setCarId(data.carId);
        }

        if (data.trackId && TRACKS.some(t => t.id === data.trackId)) {
          setTargetTrackId(data.trackId);
        }

        // Successfully analyzed via AI -> Set as Verified
        setIsVerified(true);
      }

    } catch (err: any) {
      console.error("AI Analysis Failed:", err);

      let friendlyError = "AI 识别失败，请确保截图清晰包含数据。";
      const errorStr = err.message || JSON.stringify(err);

      if (errorStr.includes("429") || errorStr.includes("RESOURCE_EXHAUSTED") || errorStr.includes("quota")) {
        friendlyError = "AI 服务配额已耗尽 (429)。请等待几秒后点击重试。";
      } else if (errorStr.includes("503") || errorStr.includes("overloaded")) {
        friendlyError = "AI 服务繁忙，请稍后再试。";
      }

      setError(friendlyError);
      setIsVerified(false); // Analysis failed, so not verified
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleManualTimeChange = (setter: React.Dispatch<React.SetStateAction<string>>, value: string) => {
    setter(value);
    // If user manually changes the time, invalidate the AI verification
    setIsVerified(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMessage('');
    setIsSubmitting(true);

    const m = parseInt(minutes);
    const s = parseInt(seconds);
    const ms = parseInt(millis);
    const tTemp = trackTemp ? parseInt(trackTemp) : undefined;

    if (isNaN(m) || isNaN(s) || isNaN(ms)) {
      setError('请输入有效的圈速。');
      setIsSubmitting(false);
      return;
    }
    if (s >= 60) {
      setError('秒数必须小于60。');
      setIsSubmitting(false);
      return;
    }
    if (ms >= 1000) {
      setError('毫秒数必须小于1000。');
      setIsSubmitting(false);
      return;
    }

    const totalMilliseconds = (m * 60 * 1000) + (s * 1000) + ms;

    const generateId = () => {
      if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
      }
      return Date.now().toString(36) + Math.random().toString(36).substr(2);
    };

    const lapData: LapTime = {
      id: initialData?.id || generateId(), // Preserve ID if editing
      username: user.username,
      userEmail: user.email, 
      trackId: targetTrackId, 
      carId,
      minutes: m,
      seconds: s,
      milliseconds: ms,
      totalMilliseconds,
      timestamp: initialData?.timestamp || new Date().toISOString(), // Preserve timestamp if editing, or use current
      conditions,
      trackTemp: tTemp,
      inputDevice,
      isVerified: isVerified
    };

    let result;
    if (isEditing) {
       // If editing, force update regardless of PB check (assumes correction)
       result = await updateLapTime(lapData);
    } else {
       // If new, use standard submission (checks PB)
       result = await submitLapTime(lapData);
    }

    if (result.success) {
      setSuccessMessage(result.message);
      setTimeout(() => {
        onSuccess();
      }, 1500);
    } else {
      setError(result.message);
    }
    setIsSubmitting(false);
  };

  const currentTrack = TRACKS.find(t => t.id === targetTrackId) || initialTrack;

  return (
    <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-2xl max-w-lg mx-auto w-full animate-fade-in-up">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold text-white flex items-center gap-2">
          <span className="text-red-500">{isEditing ? '编辑圈速' : '录入圈速'}</span>
        </h2>
        <div className="flex items-center gap-2">
          {isVerified && (
             <div className="flex items-center gap-1 text-xs bg-green-900/40 text-green-400 px-2 py-1 rounded border border-green-800">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M6.267 3.455a3.066 3.066 0 001.745-.723 3.066 3.066 0 013.976 0 3.066 3.066 0 001.745.723 3.066 3.066 0 012.812 2.812c.051.643.304 1.254.723 1.745a3.066 3.066 0 010 3.976 3.066 3.066 0 00-.723 1.745 3.066 3.066 0 01-2.812 2.812 3.066 3.066 0 00-1.745.723 3.066 3.066 0 01-3.976 0 3.066 3.066 0 00-1.745-.723 3.066 3.066 0 01-2.812-2.812 3.066 3.066 0 00-.723-1.745 3.066 3.066 0 010-3.976 3.066 3.066 0 00.723-1.745 3.066 3.066 0 012.812-2.812zm7.44 5.252a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
               </svg>
               已验证
             </div>
          )}
          <div className="text-xs bg-slate-900 px-3 py-1 rounded-full border border-slate-700 text-slate-400">
             {isEditing ? '编辑模式' : 'AI 辅助模式'}
          </div>
        </div>
      </div>

      {/* AI Upload Section - Available for both New and Edit */}
      <div className="mb-6 p-4 bg-slate-900/50 rounded-lg border border-slate-700 border-dashed hover:border-red-500/50 transition-colors">
        <input 
          type="file" 
          accept="image/*" 
          className="hidden" 
          ref={fileInputRef}
          onChange={handleImageUpload}
        />

        {!previewImage ? (
          <button 
            type="button"
            onClick={() => fileInputRef.current?.click()}
            className="w-full flex flex-col items-center justify-center gap-2 py-4 text-slate-400 hover:text-white transition-colors"
          >
            <div className="bg-slate-800 p-3 rounded-full animate-bounce">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
            </div>
            <span className="text-sm font-bold">
              {isEditing ? '上传新截图以更新数据' : '点击上传游戏截图'}
            </span>
            <span className="text-xs text-slate-500">
               {isEditing ? '这将覆盖当前数据并标记为已验证' : '必须上传截图以自动填充数据'}
            </span>
          </button>
        ) : (
          <div className="relative">
            <img 
              src={previewImage} 
              alt="Preview" 
              className="w-full h-32 object-cover rounded-lg opacity-80" 
            />
            {isAnalyzing && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/60 backdrop-blur-sm rounded-lg z-10">
                 <span className="w-8 h-8 border-4 border-red-500 border-t-transparent rounded-full animate-spin mb-2"></span>
                 <span className="text-white font-bold text-sm shadow-black drop-shadow-md">正在识别赛道与圈速...</span>
              </div>
            )}

            {!isAnalyzing && error && (
               <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/80 backdrop-blur-sm rounded-lg z-10 p-4 text-center">
                  <div className="text-red-400 text-sm font-bold mb-3">{error}</div>
                  <div className="flex gap-2">
                    <Button 
                      type="button" 
                      variant="primary" 
                      className="!py-1 !px-3 !text-xs"
                      onClick={(e) => {
                         e.stopPropagation();
                         analyzeScreenshot(previewImage);
                      }}
                    >
                      重试
                    </Button>
                    <Button 
                      type="button" 
                      variant="secondary" 
                      className="!py-1 !px-3 !text-xs"
                      onClick={() => {
                        setPreviewImage(null);
                        setError('');
                      }}
                    >
                      取消
                    </Button>
                  </div>
               </div>
            )}

            {!isAnalyzing && !error && (
              <button 
                type="button"
                onClick={() => {
                  setPreviewImage(null);
                  if (!isEditing) {
                      setMinutes('');
                      setSeconds('');
                      setMillis('');
                      setTrackTemp('');
                      setTargetTrackId(initialTrack.id);
                  }
                  setIsVerified(false); // Reset verified if image removed
                }}
                className="absolute top-2 right-2 bg-black/50 text-white rounded-full p-1 hover:bg-red-600 transition-colors z-20"
                title="清除并重新上传"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                </svg>
              </button>
            )}
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Track Display */}
        <div>
           <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">赛道</label>
           </div>
           <div className={`flex items-center gap-3 p-3 bg-slate-950 border border-slate-800 rounded-lg ${isAnalyzing ? 'opacity-50' : ''}`}>
              {currentTrack.imageUrl && (
                 <img src={currentTrack.imageUrl} className="h-8 w-8 object-contain brightness-0 invert opacity-50" alt="Track Icon"/>
              )}
              <div className="flex-1">
                 <div className="text-white font-bold">{currentTrack.name}</div>
                 <div className="text-xs text-slate-500">{currentTrack.country} • {currentTrack.length}</div>
              </div>
           </div>
        </div>

        {/* Car Selection */}
        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">车辆</label>
          <select 
            value={carId} 
            onChange={(e) => setCarId(e.target.value)}
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:border-red-500 focus:outline-none focus:ring-1 focus:ring-red-500"
          >
            {CARS.map(car => (
              <option key={car.id} value={car.id}>
                [{car.class}] {car.brand} {car.name}
              </option>
            ))}
          </select>
        </div>

        {/* Lap Time Inputs */}
        <div>
          <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">圈速成绩</label>
             {isVerified && (
               <span className="text-[10px] text-green-500 bg-green-900/20 px-1.5 rounded border border-green-800/50">已锁定验证</span>
             )}
          </div>
          <div className="flex items-end gap-2">
            <div className="flex-1">
              <Input 
                placeholder="00" 
                value={minutes}
                onChange={(e) => handleManualTimeChange(setMinutes, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="59"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">分</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">:</span>
            <div className="flex-1">
              <Input 
                placeholder="00" 
                value={seconds}
                onChange={(e) => handleManualTimeChange(setSeconds, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="59"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">秒</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">.</span>
            <div className="flex-1">
              <Input 
                placeholder="000" 
                value={millis}
                onChange={(e) => handleManualTimeChange(setMillis, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="999"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">毫秒</span>
            </div>
          </div>
          <div className="text-xs text-slate-500 mt-2 text-right">
             * 手动修改时间将取消验证状态
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">赛道温度 (°C)</label>
              <div className="relative">
                <Input
                  type="number"
                  placeholder="24"
                  value={trackTemp}
                  onChange={(e) => setTrackTemp(e.target.value)}
                  className={isAnalyzing ? 'opacity-50' : ''}
                />
                <span className="absolute right-4 top-3.5 text-slate-500">°C</span>
              </div>
           </div>

           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">输入设备</label>
              <div className="flex flex-col gap-2">
                 <div className="grid grid-cols-3 gap-2">
                    {(['Wheel', 'Gamepad', 'Keyboard'] as InputDevice[]).map((dev) => (
                      <button
                        key={dev}
                        type="button"
                        onClick={() => setInputDevice(dev)}
                        className={`flex flex-col items-center justify-center p-3 rounded-lg border transition-all ${
                          inputDevice === dev
                            ? 'bg-red-600 border-red-500 text-white shadow-lg shadow-red-900/20'
                            : 'bg-slate-900 border-slate-700 text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                        }`}
                        title={dev === 'Wheel' ? '方向盘' : dev === 'Gamepad' ? '手柄' : '键盘'}
                      >
                        <InputDeviceIcon device={dev} className="h-8 w-8" />
                      </button>
                    ))}
                 </div>
              </div>
           </div>
        </div>

        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">赛道状况</label>
          <div className="flex gap-4">
            <button
              type="button"
              onClick={() => setConditions('Dry')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Dry' 
                  ? 'bg-orange-500/20 border-orange-500 text-orange-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              ☀️ 干地
            </button>
            <button
              type="button"
              onClick={() => setConditions('Wet')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Wet' 
                  ? 'bg-blue-500/20 border-blue-500 text-blue-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              🌧️ 湿地
            </button>
          </div>
        </div>

        {error && !previewImage && (
          <div className="bg-yellow-900/50 border border-yellow-500/50 text-yellow-200 px-4 py-3 rounded text-sm font-semibold break-words">
            ⚠️ {error}
          </div>
        )}

        {successMessage && (
           <div className="bg-green-900/50 border border-green-500/50 text-green-200 px-4 py-3 rounded text-sm font-semibold flex items-center gap-2">
             ✅ {successMessage}
           </div>
        )}

        <div className="flex gap-3 pt-4">
          <Button type="button" variant="ghost" onClick={onCancel} className="flex-1" disabled={isSubmitting || isAnalyzing}>
            {isEditing ? '取消编辑' : '返回'}
          </Button>
          <Button type="submit" className="flex-1" disabled={!!successMessage || isSubmitting || isAnalyzing} isLoading={isSubmitting}>
            {isEditing ? '更新成绩' : '提交成绩'}
          </Button>
        </div>
      </form>
    </div>
  );
};

export default SubmitLapForm;

import React, { useState, useRef } from 'react';
import { Track, User, LapTime, InputDevice } from '../types';
import { CARS, TRACKS } from '../constants';
import { submitLapTime, updateLapTime } from '../services/storageService';
import Button from './Button';
import Input from './Input';
import InputDeviceIcon from './InputDeviceIcon';
import { GoogleGenAI, Type } from "@google/genai";

interface SubmitLapFormProps {
  track: Track;
  user: User;
  onSuccess: () => void;
  onCancel: () => void;
  initialData?: LapTime | null;
}

const SubmitLapForm: React.FC<SubmitLapFormProps> = ({ track: initialTrack, user, onSuccess, onCancel, initialData }) => {
  // State initialization
  const [targetTrackId, setTargetTrackId] = useState(initialData?.trackId || initialTrack.id);
  const [carId, setCarId] = useState(initialData?.carId || CARS[0].id);
  const [minutes, setMinutes] = useState(initialData?.minutes.toString() || '');
  const [seconds, setSeconds] = useState(initialData?.seconds.toString() || '');
  const [millis, setMillis] = useState(initialData?.milliseconds.toString() || '');
  const [conditions, setConditions] = useState<'Dry' | 'Wet'>(initialData?.conditions || 'Dry');
  const [trackTemp, setTrackTemp] = useState(initialData?.trackTemp?.toString() || '');
  const [inputDevice, setInputDevice] = useState<InputDevice>(initialData?.inputDevice || 'Wheel');
  const [isVerified, setIsVerified] = useState<boolean>(initialData?.isVerified || false);

  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // AI Analysis State
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const isEditing = !!initialData;

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // 1. Preview
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      setPreviewImage(base64String);
      analyzeScreenshot(base64String); // Auto-start analysis
    };
    reader.readAsDataURL(file);
  };

  const analyzeScreenshot = async (base64Full: string) => {
    setIsAnalyzing(true);
    setError('');

    try {
      // Clean base64 string (remove data:image/png;base64, prefix)
      const base64Data = base64Full.split(',')[1];
      const mimeType = base64Full.split(';')[0].split(':')[1];

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Prepare Contexts
      const carListContext = CARS.map(c => `ID: "${c.id}", Name: "${c.brand} ${c.name}"`).join('\n');
      const trackListContext = TRACKS.map(t => `ID: "${t.id}", Name: "${t.name}"`).join('\n');

      const prompt = `
        Analyze this Assetto Corsa Competizione screenshot.

        Tasks:
        1. **Fastest Lap**: Identify the FASTEST (lowest) valid lap time (MM:SS.ms) visible in the image. 
           - If a leaderboard is shown, select the row with the best time.
           - Ignore invalid laps (often red) if a valid one exists.
        2. **Car**: Identify the Car Model specifically used for that fastest lap. Match it to the provided Car List.
        3. **Track**: Identify the Track Name from the UI/Environment and match to the provided Track List.
        4. **Conditions**: Identify Track Temperature (e.g., "Track: 24°C").

        Lists:
        [CARS]
        ${carListContext}

        [TRACKS]
        ${trackListContext}
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-2.0-flash',
        contents: {
          parts: [
            { inlineData: { mimeType: mimeType, data: base64Data } },
            { text: prompt }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              minutes: { type: Type.INTEGER },
              seconds: { type: Type.INTEGER },
              milliseconds: { type: Type.INTEGER },
              carId: { type: Type.STRING, description: "ID from Car List" },
              trackId: { type: Type.STRING, description: "ID from Track List" },
              trackTemp: { type: Type.INTEGER },
            },
            required: ["minutes", "seconds", "milliseconds"]
          }
        }
      });

      const resultText = response.text;
      if (resultText) {
        let cleanText = resultText.trim();
        // Robust cleaning of markdown code blocks
        if (cleanText.startsWith('```')) {
            cleanText = cleanText.replace(/^```json\s?/, '').replace(/^```\s?/, '').replace(/```$/, '');
        }

        const data = JSON.parse(cleanText);

        if (data.minutes !== undefined) setMinutes(data.minutes.toString());
        if (data.seconds !== undefined) setSeconds(data.seconds.toString());
        if (data.milliseconds !== undefined) setMillis(data.milliseconds.toString());
        if (data.trackTemp !== undefined) setTrackTemp(data.trackTemp.toString());

        if (data.carId && CARS.some(c => c.id === data.carId)) {
          setCarId(data.carId);
        }

        if (data.trackId && TRACKS.some(t => t.id === data.trackId)) {
          setTargetTrackId(data.trackId);
        }

        // Successfully analyzed via AI -> Set as Verified
        setIsVerified(true);
      }

    } catch (err: any) {
      console.error("AI Analysis Failed:", err);

      let friendlyError = "AI 识别失败，请确保截图清晰包含数据。";
      const errorStr = err.message || JSON.stringify(err);

      if (errorStr.includes("429") || errorStr.includes("RESOURCE_EXHAUSTED") || errorStr.includes("quota")) {
        friendlyError = "AI 服务配额已耗尽 (429)。请等待几秒后点击重试。";
      } else if (errorStr.includes("503") || errorStr.includes("overloaded")) {
        friendlyError = "AI 服务繁忙，请稍后再试。";
      }

      setError(friendlyError);
      setIsVerified(false); // Analysis failed, so not verified
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleManualTimeChange = (setter: React.Dispatch<React.SetStateAction<string>>, value: string) => {
    setter(value);
    // If user manually changes the time, invalidate the AI verification
    setIsVerified(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMessage('');
    setIsSubmitting(true);

    const m = parseInt(minutes);
    const s = parseInt(seconds);
    const ms = parseInt(millis);
    const tTemp = trackTemp ? parseInt(trackTemp) : undefined;

    if (isNaN(m) || isNaN(s) || isNaN(ms)) {
      setError('请输入有效的圈速。');
      setIsSubmitting(false);
      return;
    }
    if (s >= 60) {
      setError('秒数必须小于60。');
      setIsSubmitting(false);
      return;
    }
    if (ms >= 1000) {
      setError('毫秒数必须小于1000。');
      setIsSubmitting(false);
      return;
    }

    const totalMilliseconds = (m * 60 * 1000) + (s * 1000) + ms;

    const generateId = () => {
      if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
      }
      return Date.now().toString(36) + Math.random().toString(36).substr(2);
    };

    const lapData: LapTime = {
      id: initialData?.id || generateId(), // Preserve ID if editing
      username: user.username,
      userEmail: user.email, 
      trackId: targetTrackId, 
      carId,
      minutes: m,
      seconds: s,
      milliseconds: ms,
      totalMilliseconds,
      timestamp: initialData?.timestamp || new Date().toISOString(), // Preserve timestamp if editing, or use current
      conditions,
      trackTemp: tTemp,
      inputDevice,
      isVerified: isVerified
    };

    let result;
    if (isEditing) {
       // If editing, force update regardless of PB check (assumes correction)
       result = await updateLapTime(lapData);
    } else {
       // If new, use standard submission (checks PB)
       result = await submitLapTime(lapData);
    }

    if (result.success) {
      setSuccessMessage(result.message);
      setTimeout(() => {
        onSuccess();
      }, 1500);
    } else {
      setError(result.message);
    }
    setIsSubmitting(false);
  };

  const currentTrack = TRACKS.find(t => t.id === targetTrackId) || initialTrack;

  return (
    <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-2xl max-w-lg mx-auto w-full animate-fade-in-up">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold text-white flex items-center gap-2">
          <span className="text-red-500">{isEditing ? '编辑圈速' : '录入圈速'}</span>
        </h2>
        <div className="flex items-center gap-2">
          {isVerified && (
             <div className="flex items-center gap-1 text-xs bg-green-900/40 text-green-400 px-2 py-1 rounded border border-green-800">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M6.267 3.455a3.066 3.066 0 001.745-.723 3.066 3.066 0 013.976 0 3.066 3.066 0 001.745.723 3.066 3.066 0 012.812 2.812c.051.643.304 1.254.723 1.745a3.066 3.066 0 010 3.976 3.066 3.066 0 00-.723 1.745 3.066 3.066 0 01-2.812 2.812 3.066 3.066 0 00-1.745.723 3.066 3.066 0 01-3.976 0 3.066 3.066 0 00-1.745-.723 3.066 3.066 0 01-2.812-2.812 3.066 3.066 0 00-.723-1.745 3.066 3.066 0 010-3.976 3.066 3.066 0 00.723-1.745 3.066 3.066 0 012.812-2.812zm7.44 5.252a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
               </svg>
               已验证
             </div>
          )}
          <div className="text-xs bg-slate-900 px-3 py-1 rounded-full border border-slate-700 text-slate-400">
             {isEditing ? '编辑模式' : 'AI 辅助模式'}
          </div>
        </div>
      </div>

      {/* AI Upload Section - Available for both New and Edit */}
      <div className="mb-6 p-4 bg-slate-900/50 rounded-lg border border-slate-700 border-dashed hover:border-red-500/50 transition-colors">
        <input 
          type="file" 
          accept="image/*" 
          className="hidden" 
          ref={fileInputRef}
          onChange={handleImageUpload}
        />

        {!previewImage ? (
          <button 
            type="button"
            onClick={() => fileInputRef.current?.click()}
            className="w-full flex flex-col items-center justify-center gap-2 py-4 text-slate-400 hover:text-white transition-colors"
          >
            <div className="bg-slate-800 p-3 rounded-full animate-bounce">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
            </div>
            <span className="text-sm font-bold">
              {isEditing ? '上传新截图以更新数据' : '点击上传游戏截图'}
            </span>
            <span className="text-xs text-slate-500">
               {isEditing ? '这将覆盖当前数据并标记为已验证' : '必须上传截图以自动填充数据'}
            </span>
          </button>
        ) : (
          <div className="relative">
            <img 
              src={previewImage} 
              alt="Preview" 
              className="w-full h-32 object-cover rounded-lg opacity-80" 
            />
            {isAnalyzing && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/60 backdrop-blur-sm rounded-lg z-10">
                 <span className="w-8 h-8 border-4 border-red-500 border-t-transparent rounded-full animate-spin mb-2"></span>
                 <span className="text-white font-bold text-sm shadow-black drop-shadow-md">正在识别赛道与圈速...</span>
              </div>
            )}

            {!isAnalyzing && error && (
               <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/80 backdrop-blur-sm rounded-lg z-10 p-4 text-center">
                  <div className="text-red-400 text-sm font-bold mb-3">{error}</div>
                  <div className="flex gap-2">
                    <Button 
                      type="button" 
                      variant="primary" 
                      className="!py-1 !px-3 !text-xs"
                      onClick={(e) => {
                         e.stopPropagation();
                         analyzeScreenshot(previewImage);
                      }}
                    >
                      重试
                    </Button>
                    <Button 
                      type="button" 
                      variant="secondary" 
                      className="!py-1 !px-3 !text-xs"
                      onClick={() => {
                        setPreviewImage(null);
                        setError('');
                      }}
                    >
                      取消
                    </Button>
                  </div>
               </div>
            )}

            {!isAnalyzing && !error && (
              <button 
                type="button"
                onClick={() => {
                  setPreviewImage(null);
                  if (!isEditing) {
                      setMinutes('');
                      setSeconds('');
                      setMillis('');
                      setTrackTemp('');
                      setTargetTrackId(initialTrack.id);
                  }
                  setIsVerified(false); // Reset verified if image removed
                }}
                className="absolute top-2 right-2 bg-black/50 text-white rounded-full p-1 hover:bg-red-600 transition-colors z-20"
                title="清除并重新上传"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                </svg>
              </button>
            )}
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Track Display */}
        <div>
           <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">赛道</label>
           </div>
           <div className={`flex items-center gap-3 p-3 bg-slate-950 border border-slate-800 rounded-lg ${isAnalyzing ? 'opacity-50' : ''}`}>
              {currentTrack.imageUrl && (
                 <img src={currentTrack.imageUrl} className="h-8 w-8 object-contain brightness-0 invert opacity-50" alt="Track Icon"/>
              )}
              <div className="flex-1">
                 <div className="text-white font-bold">{currentTrack.name}</div>
                 <div className="text-xs text-slate-500">{currentTrack.country} • {currentTrack.length}</div>
              </div>
           </div>
        </div>

        {/* Car Selection */}
        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">车辆</label>
          <select 
            value={carId} 
            onChange={(e) => setCarId(e.target.value)}
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:border-red-500 focus:outline-none focus:ring-1 focus:ring-red-500"
          >
            {CARS.map(car => (
              <option key={car.id} value={car.id}>
                [{car.class}] {car.brand} {car.name}
              </option>
            ))}
          </select>
        </div>

        {/* Lap Time Inputs */}
        <div>
          <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">圈速成绩</label>
             {isVerified && (
               <span className="text-[10px] text-green-500 bg-green-900/20 px-1.5 rounded border border-green-800/50">已锁定验证</span>
             )}
          </div>
          <div className="flex items-end gap-2">
            <div className="flex-1">
              <Input 
                placeholder="00" 
                value={minutes}
                onChange={(e) => handleManualTimeChange(setMinutes, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="59"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">分</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">:</span>
            <div className="flex-1">
              <Input 
                placeholder="00" 
                value={seconds}
                onChange={(e) => handleManualTimeChange(setSeconds, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="59"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">秒</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">.</span>
            <div className="flex-1">
              <Input 
                placeholder="000" 
                value={millis}
                onChange={(e) => handleManualTimeChange(setMillis, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="999"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">毫秒</span>
            </div>
          </div>
          <div className="text-xs text-slate-500 mt-2 text-right">
             * 手动修改时间将取消验证状态
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">赛道温度 (°C)</label>
              <div className="relative">
                <Input
                  type="number"
                  placeholder="24"
                  value={trackTemp}
                  onChange={(e) => setTrackTemp(e.target.value)}
                  className={isAnalyzing ? 'opacity-50' : ''}
                />
                <span className="absolute right-4 top-3.5 text-slate-500">°C</span>
              </div>
           </div>

           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">输入设备</label>
              <div className="flex flex-col gap-2">
                 <div className="grid grid-cols-3 gap-2">
                    {(['Wheel', 'Gamepad', 'Keyboard'] as InputDevice[]).map((dev) => (
                      <button
                        key={dev}
                        type="button"
                        onClick={() => setInputDevice(dev)}
                        className={`flex flex-col items-center justify-center p-3 rounded-lg border transition-all ${
                          inputDevice === dev
                            ? 'bg-red-600 border-red-500 text-white shadow-lg shadow-red-900/20'
                            : 'bg-slate-900 border-slate-700 text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                        }`}
                        title={dev === 'Wheel' ? '方向盘' : dev === 'Gamepad' ? '手柄' : '键盘'}
                      >
                        <InputDeviceIcon device={dev} className="h-8 w-8" />
                      </button>
                    ))}
                 </div>
              </div>
           </div>
        </div>

        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">赛道状况</label>
          <div className="flex gap-4">
            <button
              type="button"
              onClick={() => setConditions('Dry')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Dry' 
                  ? 'bg-orange-500/20 border-orange-500 text-orange-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              ☀️ 干地
            </button>
            <button
              type="button"
              onClick={() => setConditions('Wet')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Wet' 
                  ? 'bg-blue-500/20 border-blue-500 text-blue-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              🌧️ 湿地
            </button>
          </div>
        </div>

        {error && !previewImage && (
          <div className="bg-yellow-900/50 border border-yellow-500/50 text-yellow-200 px-4 py-3 rounded text-sm font-semibold break-words">
            ⚠️ {error}
          </div>
        )}

        {successMessage && (
           <div className="bg-green-900/50 border border-green-500/50 text-green-200 px-4 py-3 rounded text-sm font-semibold flex items-center gap-2">
             ✅ {successMessage}
           </div>
        )}

        <div className="flex gap-3 pt-4">
          <Button type="button" variant="ghost" onClick={onCancel} className="flex-1" disabled={isSubmitting || isAnalyzing}>
            {isEditing ? '取消编辑' : '返回'}
          </Button>
          <Button type="submit" className="flex-1" disabled={!!successMessage || isSubmitting || isAnalyzing} isLoading={isSubmitting}>
            {isEditing ? '更新成绩' : '提交成绩'}
          </Button>
        </div>
      </form>
    </div>
  );
};

export default SubmitLapForm;

import React, { useState, useRef } from 'react';
import { Track, User, LapTime, InputDevice } from '../types';
import { CARS, TRACKS } from '../constants';
import { submitLapTime, updateLapTime } from '../services/storageService';
import Button from './Button';
import Input from './Input';
import InputDeviceIcon from './InputDeviceIcon';
import { GoogleGenAI, Type } from "@google/genai";

interface SubmitLapFormProps {
  track: Track;
  user: User;
  onSuccess: () => void;
  onCancel: () => void;
  initialData?: LapTime | null;
}

const SubmitLapForm: React.FC<SubmitLapFormProps> = ({ track: initialTrack, user, onSuccess, onCancel, initialData }) => {
  // State initialization
  const [targetTrackId, setTargetTrackId] = useState(initialData?.trackId || initialTrack.id);
  const [carId, setCarId] = useState(initialData?.carId || CARS[0].id);
  const [minutes, setMinutes] = useState(initialData?.minutes.toString() || '');
  const [seconds, setSeconds] = useState(initialData?.seconds.toString() || '');
  const [millis, setMillis] = useState(initialData?.milliseconds.toString() || '');
  const [conditions, setConditions] = useState<'Dry' | 'Wet'>(initialData?.conditions || 'Dry');
  const [trackTemp, setTrackTemp] = useState(initialData?.trackTemp?.toString() || '');
  const [inputDevice, setInputDevice] = useState<InputDevice>(initialData?.inputDevice || 'Wheel');
  const [isVerified, setIsVerified] = useState<boolean>(initialData?.isVerified || false);

  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // AI Analysis State
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const isEditing = !!initialData;

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // 1. Preview
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      setPreviewImage(base64String);
      // Removed automatic call to analyzeScreenshot to save quota
      setIsVerified(false);
      setError('');
    };
    reader.readAsDataURL(file);
  };

  const analyzeScreenshot = async (base64Full: string) => {
    setIsAnalyzing(true);
    setError('');

    try {
      // Clean base64 string (remove data:image/png;base64, prefix)
      const base64Data = base64Full.split(',')[1];
      const mimeType = base64Full.split(';')[0].split(':')[1];

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Prepare Contexts
      const carListContext = CARS.map(c => `ID: "${c.id}", Name: "${c.brand} ${c.name}"`).join('\n');
      const trackListContext = TRACKS.map(t => `ID: "${t.id}", Name: "${t.name}"`).join('\n');

      const prompt = `
        Analyze this Assetto Corsa Competizione screenshot.

        Tasks:
        1. **Fastest Lap**: Identify the FASTEST (lowest) valid lap time (MM:SS.ms) visible in the image. 
           - If a leaderboard is shown, select the row with the best time.
           - Ignore invalid laps (often red) if a valid one exists.
        2. **Car**: Identify the Car Model specifically used for that fastest lap. Match it to the provided Car List.
        3. **Track**: Identify the Track Name from the UI/Environment and match to the provided Track List.
        4. **Conditions**: Identify Track Temperature (e.g., "Track: 24°C").

        Lists:
        [CARS]
        ${carListContext}

        [TRACKS]
        ${trackListContext}
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-2.0-flash',
        contents: {
          parts: [
            { inlineData: { mimeType: mimeType, data: base64Data } },
            { text: prompt }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              minutes: { type: Type.INTEGER },
              seconds: { type: Type.INTEGER },
              milliseconds: { type: Type.INTEGER },
              carId: { type: Type.STRING, description: "ID from Car List" },
              trackId: { type: Type.STRING, description: "ID from Track List" },
              trackTemp: { type: Type.INTEGER },
            },
            required: ["minutes", "seconds", "milliseconds"]
          }
        }
      });

      const resultText = response.text;
      if (resultText) {
        let cleanText = resultText.trim();
        // Robust cleaning of markdown code blocks
        if (cleanText.startsWith('```')) {
            cleanText = cleanText.replace(/^```json\s?/, '').replace(/^```\s?/, '').replace(/```$/, '');
        }

        const data = JSON.parse(cleanText);

        if (data.minutes !== undefined) setMinutes(data.minutes.toString());
        if (data.seconds !== undefined) setSeconds(data.seconds.toString());
        if (data.milliseconds !== undefined) setMillis(data.milliseconds.toString());
        if (data.trackTemp !== undefined) setTrackTemp(data.trackTemp.toString());

        if (data.carId && CARS.some(c => c.id === data.carId)) {
          setCarId(data.carId);
        }

        if (data.trackId && TRACKS.some(t => t.id === data.trackId)) {
          setTargetTrackId(data.trackId);
        }

        // Successfully analyzed via AI -> Set as Verified
        setIsVerified(true);
      }

    } catch (err: any) {
      console.error("AI Analysis Failed:", err);

      let friendlyError = "AI 识别失败，请确保截图清晰包含数据。";
      const errorStr = err.message || JSON.stringify(err);

      if (errorStr.includes("429") || errorStr.includes("RESOURCE_EXHAUSTED") || errorStr.includes("quota")) {
        friendlyError = "AI 配额耗尽 (429)。免费版 API 有频率限制，请稍候再点击识别。";
      } else if (errorStr.includes("503") || errorStr.includes("overloaded")) {
        friendlyError = "AI 服务繁忙，请稍后再试。";
      }

      setError(friendlyError);
      setIsVerified(false); // Analysis failed, so not verified
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleManualTimeChange = (setter: React.Dispatch<React.SetStateAction<string>>, value: string) => {
    setter(value);
    // If user manually changes the time, invalidate the AI verification
    setIsVerified(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMessage('');
    setIsSubmitting(true);

    const m = parseInt(minutes);
    const s = parseInt(seconds);
    const ms = parseInt(millis);
    const tTemp = trackTemp ? parseInt(trackTemp) : undefined;

    if (isNaN(m) || isNaN(s) || isNaN(ms)) {
      setError('请输入有效的圈速。');
      setIsSubmitting(false);
      return;
    }
    if (s >= 60) {
      setError('秒数必须小于60。');
      setIsSubmitting(false);
      return;
    }
    if (ms >= 1000) {
      setError('毫秒数必须小于1000。');
      setIsSubmitting(false);
      return;
    }

    const totalMilliseconds = (m * 60 * 1000) + (s * 1000) + ms;

    const generateId = () => {
      if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
      }
      return Date.now().toString(36) + Math.random().toString(36).substr(2);
    };

    const lapData: LapTime = {
      id: initialData?.id || generateId(), // Preserve ID if editing
      username: user.username,
      userEmail: user.email, 
      trackId: targetTrackId, 
      carId,
      minutes: m,
      seconds: s,
      milliseconds: ms,
      totalMilliseconds,
      timestamp: initialData?.timestamp || new Date().toISOString(), // Preserve timestamp if editing, or use current
      conditions,
      trackTemp: tTemp,
      inputDevice,
      isVerified: isVerified
    };

    let result;
    if (isEditing) {
       // If editing, force update regardless of PB check (assumes correction)
       result = await updateLapTime(lapData);
    } else {
       // If new, use standard submission (checks PB)
       result = await submitLapTime(lapData);
    }

    if (result.success) {
      setSuccessMessage(result.message);
      setTimeout(() => {
        onSuccess();
      }, 1500);
    } else {
      setError(result.message);
    }
    setIsSubmitting(false);
  };

  const currentTrack = TRACKS.find(t => t.id === targetTrackId) || initialTrack;

  return (
    <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-2xl max-w-lg mx-auto w-full animate-fade-in-up">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold text-white flex items-center gap-2">
          <span className="text-red-500">{isEditing ? '编辑圈速' : '录入圈速'}</span>
        </h2>
        <div className="flex items-center gap-2">
          {isVerified && (
             <div className="flex items-center gap-1 text-xs bg-green-900/40 text-green-400 px-2 py-1 rounded border border-green-800">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M6.267 3.455a3.066 3.066 0 001.745-.723 3.066 3.066 0 013.976 0 3.066 3.066 0 001.745.723 3.066 3.066 0 012.812 2.812c.051.643.304 1.254.723 1.745a3.066 3.066 0 010 3.976 3.066 3.066 0 00-.723 1.745 3.066 3.066 0 01-2.812 2.812 3.066 3.066 0 00-1.745.723 3.066 3.066 0 01-3.976 0 3.066 3.066 0 00-1.745-.723 3.066 3.066 0 01-2.812-2.812 3.066 3.066 0 00-.723-1.745 3.066 3.066 0 010-3.976 3.066 3.066 0 00.723-1.745 3.066 3.066 0 012.812-2.812zm7.44 5.252a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
               </svg>
               已验证
             </div>
          )}
          <div className="text-xs bg-slate-900 px-3 py-1 rounded-full border border-slate-700 text-slate-400">
             {isEditing ? '编辑模式' : 'AI 辅助模式'}
          </div>
        </div>
      </div>

      {/* AI Upload Section */}
      <div className="mb-6 p-4 bg-slate-900/50 rounded-lg border border-slate-700 border-dashed hover:border-red-500/50 transition-colors">
        <input 
          type="file" 
          accept="image/*" 
          className="hidden" 
          ref={fileInputRef}
          onChange={handleImageUpload}
        />

        {!previewImage ? (
          <button 
            type="button"
            onClick={() => fileInputRef.current?.click()}
            className="w-full flex flex-col items-center justify-center gap-2 py-4 text-slate-400 hover:text-white transition-colors"
          >
            <div className="bg-slate-800 p-3 rounded-full animate-bounce">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
            </div>
            <span className="text-sm font-bold">
              {isEditing ? '上传新截图以更新数据' : '点击上传游戏截图'}
            </span>
            <span className="text-xs text-slate-500">
               {isEditing ? '这将覆盖当前数据' : '上传截图后手动点击识别'}
            </span>
          </button>
        ) : (
          <div className="relative">
            <img 
              src={previewImage} 
              alt="Preview" 
              className="w-full h-32 object-cover rounded-lg opacity-80" 
            />

            {/* Loading State */}
            {isAnalyzing && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/80 backdrop-blur-sm rounded-lg z-10">
                 <span className="w-8 h-8 border-4 border-red-500 border-t-transparent rounded-full animate-spin mb-2"></span>
                 <span className="text-white font-bold text-sm shadow-black drop-shadow-md">正在识别赛道与圈速...</span>
              </div>
            )}

            {/* Manual Trigger Button (Only show if NOT analyzing and NOT verified yet) */}
            {!isAnalyzing && !isVerified && !error && (
               <div className="absolute inset-0 flex items-center justify-center bg-black/40 hover:bg-black/50 transition-colors rounded-lg z-10">
                   <Button 
                      onClick={() => analyzeScreenshot(previewImage)}
                      variant="primary"
                      className="shadow-xl scale-110 !px-6 !py-2"
                   >
                      🤖 开始 AI 识别
                   </Button>
               </div>
            )}

            {/* Error State with Retry */}
            {!isAnalyzing && error && (
               <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/90 backdrop-blur-sm rounded-lg z-10 p-4 text-center">
                  <div className="text-red-400 text-sm font-bold mb-3">{error}</div>
                  <div className="flex gap-2">
                    <Button 
                      type="button" 
                      variant="primary" 
                      className="!py-1 !px-3 !text-xs"
                      onClick={(e) => {
                         e.stopPropagation();
                         analyzeScreenshot(previewImage);
                      }}
                    >
                      重试
                    </Button>
                    <Button 
                      type="button" 
                      variant="secondary" 
                      className="!py-1 !px-3 !text-xs"
                      onClick={() => {
                        setPreviewImage(null);
                        setError('');
                      }}
                    >
                      重新上传
                    </Button>
                  </div>
               </div>
            )}

            {/* Delete/Clear Button */}
            {!isAnalyzing && (
              <button 
                type="button"
                onClick={() => {
                  setPreviewImage(null);
                  setError('');
                  if (!isEditing) {
                      setMinutes('');
                      setSeconds('');
                      setMillis('');
                      setTrackTemp('');
                      setTargetTrackId(initialTrack.id);
                  }
                  setIsVerified(false);
                }}
                className="absolute top-2 right-2 bg-black/50 text-white rounded-full p-1 hover:bg-red-600 transition-colors z-20"
                title="清除图片"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                </svg>
              </button>
            )}
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Track Display */}
        <div>
           <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">赛道</label>
           </div>
           <div className={`flex items-center gap-3 p-3 bg-slate-950 border border-slate-800 rounded-lg ${isAnalyzing ? 'opacity-50' : ''}`}>
              {currentTrack.imageUrl && (
                 <img src={currentTrack.imageUrl} className="h-8 w-8 object-contain brightness-0 invert opacity-50" alt="Track Icon"/>
              )}
              <div className="flex-1">
                 <div className="text-white font-bold">{currentTrack.name}</div>
                 <div className="text-xs text-slate-500">{currentTrack.country} • {currentTrack.length}</div>
              </div>
           </div>
        </div>

        {/* Car Selection */}
        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">车辆</label>
          <select 
            value={carId} 
            onChange={(e) => setCarId(e.target.value)}
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:border-red-500 focus:outline-none focus:ring-1 focus:ring-red-500"
          >
            {CARS.map(car => (
              <option key={car.id} value={car.id}>
                [{car.class}] {car.brand} {car.name}
              </option>
            ))}
          </select>
        </div>

        {/* Lap Time Inputs */}
        <div>
          <div className="flex items-center gap-2 mb-2">
             <label className="block text-slate-400 text-sm font-bold">圈速成绩</label>
             {isVerified && (
               <span className="text-[10px] text-green-500 bg-green-900/20 px-1.5 rounded border border-green-800/50">已锁定验证</span>
             )}
          </div>
          <div className="flex items-end gap-2">
            <div className="flex-1">
              <Input 
                placeholder="00" 
                value={minutes}
                onChange={(e) => handleManualTimeChange(setMinutes, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="59"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">分</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">:</span>
            <div className="flex-1">
              <Input 
                placeholder="00" 
                value={seconds}
                onChange={(e) => handleManualTimeChange(setSeconds, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="59"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">秒</span>
            </div>
            <span className="text-2xl text-slate-500 pb-8">.</span>
            <div className="flex-1">
              <Input 
                placeholder="000" 
                value={millis}
                onChange={(e) => handleManualTimeChange(setMillis, e.target.value)}
                className={`text-center font-mono ${isAnalyzing ? 'opacity-50' : ''}`}
                type="number"
                min="0"
                max="999"
              />
              <span className="text-xs text-slate-500 text-center block mt-1">毫秒</span>
            </div>
          </div>
          <div className="text-xs text-slate-500 mt-2 text-right">
             * 手动修改时间将取消验证状态
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">赛道温度 (°C)</label>
              <div className="relative">
                <Input
                  type="number"
                  placeholder="24"
                  value={trackTemp}
                  onChange={(e) => setTrackTemp(e.target.value)}
                  className={isAnalyzing ? 'opacity-50' : ''}
                />
                <span className="absolute right-4 top-3.5 text-slate-500">°C</span>
              </div>
           </div>

           <div>
              <label className="block text-slate-400 text-sm font-bold mb-2">输入设备</label>
              <div className="flex flex-col gap-2">
                 <div className="grid grid-cols-3 gap-2">
                    {(['Wheel', 'Gamepad', 'Keyboard'] as InputDevice[]).map((dev) => (
                      <button
                        key={dev}
                        type="button"
                        onClick={() => setInputDevice(dev)}
                        className={`flex flex-col items-center justify-center p-3 rounded-lg border transition-all ${
                          inputDevice === dev
                            ? 'bg-red-600 border-red-500 text-white shadow-lg shadow-red-900/20'
                            : 'bg-slate-900 border-slate-700 text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                        }`}
                        title={dev === 'Wheel' ? '方向盘' : dev === 'Gamepad' ? '手柄' : '键盘'}
                      >
                        <InputDeviceIcon device={dev} className="h-8 w-8" />
                      </button>
                    ))}
                 </div>
              </div>
           </div>
        </div>

        <div>
          <label className="block text-slate-400 text-sm font-bold mb-2">赛道状况</label>
          <div className="flex gap-4">
            <button
              type="button"
              onClick={() => setConditions('Dry')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Dry' 
                  ? 'bg-orange-500/20 border-orange-500 text-orange-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              ☀️ 干地
            </button>
            <button
              type="button"
              onClick={() => setConditions('Wet')}
              className={`flex-1 py-3 rounded-lg font-bold border ${
                conditions === 'Wet' 
                  ? 'bg-blue-500/20 border-blue-500 text-blue-500' 
                  : 'bg-slate-900 border-slate-700 text-slate-500 hover:bg-slate-800'
              }`}
            >
              🌧️ 湿地
            </button>
          </div>
        </div>

        {error && !previewImage && (
          <div className="bg-yellow-900/50 border border-yellow-500/50 text-yellow-200 px-4 py-3 rounded text-sm font-semibold break-words">
            ⚠️ {error}
          </div>
        )}

        {successMessage && (
           <div className="bg-green-900/50 border border-green-500/50 text-green-200 px-4 py-3 rounded text-sm font-semibold flex items-center gap-2">
             ✅ {successMessage}
           </div>
        )}

        <div className="flex gap-3 pt-4">
          <Button type="button" variant="ghost" onClick={onCancel} className="flex-1" disabled={isSubmitting || isAnalyzing}>
            {isEditing ? '取消编辑' : '返回'}
          </Button>
          <Button type="submit" className="flex-1" disabled={!!successMessage || isSubmitting || isAnalyzing} isLoading={isSubmitting}>
            {isEditing ? '更新成绩' : '提交成绩'}
          </Button>
        </div>
      </form>
    </div>
  );
};

export default SubmitLapForm;

import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

// https://vitejs.dev/config/
export default defineConfig({
  plugins: [react()],
  build: {
    chunkSizeWarningLimit: 1600,
    rollupOptions: {
      output: {
        manualChunks: {
